import { db, storage, auth } from '../firebaseConfig';
import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  updateDoc, 
  doc, 
  getDoc,
  setDoc,
  Timestamp,
  writeBatch,
  deleteField,
  onSnapshot,
  orderBy,
  limit,
  increment,
  serverTimestamp,
  deleteDoc
} from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL, deleteObject } from 'firebase/storage';
import { Talent, User, UserRole, VideoRequest, RequestStatus, Payment, VideoMetadata, AuditLog, AdminSettings, ChatMessage, Conversation } from '../types';
import { MOCK_TALENTS, DB_CATEGORIES_SEED, DEFAULT_ADMIN_SETTINGS, ADMIN_EMAIL } from '../constants';

// --- UTILS & LOGGING ---

export const logAction = async (userId: string, action: string, details: string, entityId?: string) => {
  try {
    await addDoc(collection(db, 'audit_logs'), {
      userId,
      action,
      details,
      entityId,
      timestamp: new Date().toISOString()
    } as Omit<AuditLog, 'id'>);
    console.log(`[AUDIT] ${action}: ${details}`);
  } catch (e) {
    console.error("Errore scrittura audit log:", e);
  }
};

// Helper per gestire l'utente corrente nel DB
export const syncUserToDB = async (user: User) => {
  const userRef = doc(db, 'users', user.id);
  const userSnap = await getDoc(userRef);

  // LOGICA SPECIALE ADMIN HARDCODED
  // Se l'email corrisponde all'admin supremo, forziamo il ruolo ADMIN
  let role = user.role;
  if (user.email === ADMIN_EMAIL) {
      role = UserRole.ADMIN;
  }

  if (!userSnap.exists()) {
    // Se è il primo login, salviamo l'utente
    await setDoc(userRef, {
      ...user,
      role: role, // Applica ruolo calcolato
      createdAt: new Date().toISOString()
    });
    await logAction(user.id, 'login_first_time', 'Nuovo utente registrato');
  } else {
    // Se esiste, ritorniamo i dati aggiornati (es. ruolo cambiato)
    const data = userSnap.data();

    // Check se dobbiamo aggiornare il ruolo admin se non lo era
    if (user.email === ADMIN_EMAIL && data.role !== UserRole.ADMIN) {
        await updateDoc(userRef, { role: UserRole.ADMIN });
        data.role = UserRole.ADMIN;
    }

    await logAction(user.id, 'login', 'Utente loggato');
    return { ...user, ...data } as User;
  }
  return { ...user, role };
};

