// --- ADMIN SETTINGS ---

export const getAdminSettings = async (): Promise<AdminSettings> => {
    try {
        const settingsRef = doc(db, 'settings', 'global');
        const snap = await getDoc(settingsRef);

        if (snap.exists()) {
            return snap.data() as AdminSettings;
        } else {
            // Se non esiste, crea con default
            await setDoc(settingsRef, DEFAULT_ADMIN_SETTINGS);
            return DEFAULT_ADMIN_SETTINGS;
        }
    } catch (e) {
        console.error("Errore fetch admin settings:", e);
        return DEFAULT_ADMIN_SETTINGS;
    }
};

export const saveAdminSettings = async (settings: AdminSettings) => {
    try {
        const settingsRef = doc(db, 'settings', 'global');
        await setDoc(settingsRef, settings);
        if (auth.currentUser) {
            await logAction(auth.currentUser.uid, 'update_admin_settings', 'Aggiornate impostazioni globali');
        }
    } catch (e) {
        console.error("Errore salvataggio admin settings:", e);
        throw e;
    }
};

export const uploadWatermark = async (file: Blob): Promise<string> => {
    // Check file size (max 500KB for Firestore safety and performance)
    if (file.size > 500 * 1024) {
        throw new Error("Il file è troppo grande. La dimensione massima per la filigrana è 500KB.");
    }

    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = async () => {
            try {
                const base64String = reader.result as string;

                // Update Firestore settings with Base64 string directly
                // This avoids CORS issues completely as it's treated as data
                const settingsRef = doc(db, 'settings', 'global');
                await updateDoc(settingsRef, {
                    watermarkUrl: base64String
                });

                if (auth.currentUser) {
                    await logAction(auth.currentUser.uid, 'upload_watermark', 'Caricata nuova filigrana (Base64)');
                }

                resolve(base64String);
            } catch (error) {
                reject(error);
            }
        };
        reader.onerror = (error) => reject(error);
    });
};

export const deleteWatermark = async () => {
    const settingsRef = doc(db, 'settings', 'global');
    await updateDoc(settingsRef, {
        watermarkUrl: deleteField()
    });

    if (auth.currentUser) {
        await logAction(auth.currentUser.uid, 'delete_watermark', 'Eliminata filigrana');
    }
};

// --- CATEGORIES (OPTION SET) ---

export const getCategories = async (): Promise<string[]> => {
    try {
        const categoriesRef = collection(db, 'categories');
        const snapshot = await getDocs(categoriesRef);

        if (snapshot.empty) {
            console.log("⚠️ Collezione Categorie vuota. Inizio auto-seeding...");
            const batch = writeBatch(db);

            DB_CATEGORIES_SEED.forEach(catName => {
                const docRef = doc(categoriesRef); // Auto-ID
                batch.set(docRef, { name: catName });
            });

            await batch.commit();
            console.log("✅ Categorie create con successo nel DB.");
            return DB_CATEGORIES_SEED.sort();
        }

        const categories: string[] = [];
        snapshot.forEach(doc => {
            const data = doc.data();
            if (data.name) categories.push(data.name);
        });

        return categories.sort();

    } catch (error) {
        console.error("Errore fetch categorie:", error);
        return DB_CATEGORIES_SEED; // Fallback locale
    }
};

// --- TALENTS ---

export const getTalents = async (): Promise<Talent[]> => {
  try {
    const q = query(collection(db, 'users'), where('role', '==', UserRole.TALENT));
    const querySnapshot = await getDocs(q);

    const talents: Talent[] = [];
    querySnapshot.forEach((doc) => {
      const data = doc.data();
      // Ensure defaults
      talents.push({ 
        id: doc.id, 
        isAvailable: data.isAvailable !== false, // default true
        ...data 
      } as Talent);
    });

    if (talents.length === 0) {
      return MOCK_TALENTS.map(t => ({ ...t, isAvailable: true }));
    }

    return talents;
  } catch (error) {
    console.error("Errore fetch talent:", error);
    return MOCK_TALENTS.map(t => ({ ...t, isAvailable: true }));
  }
};

export const getTalentById = async (id: string): Promise<Talent | undefined> => {
  try {
    const docRef = doc(db, 'users', id);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
      const data = docSnap.data();
      return { 
        id: docSnap.id, 
        isAvailable: data.isAvailable !== false,
        ...data 
      } as Talent;
    }
    return MOCK_TALENTS.find(t => t.id === id);
  } catch (error) {
    console.error("Errore getTalentById:", error);
    return MOCK_TALENTS.find(t => t.id === id);
  }
};

// --- REQUESTS & PAYMENTS & LIFECYCLE ---

export const createRequest = async (request: Omit<VideoRequest, 'id' | 'createdAt' | 'status' | 'updatedAt'>): Promise<string> => {
  try {
    // Recupera le impostazioni globali per calcolare la scadenza
    const settings = await getAdminSettings();
    const now = new Date();

    let expiresAt = new Date(now.getTime() + settings.deliveryDeadlineDays * 24 * 60 * 60 * 1000);

    // Se è Flash Delivery, scade in 24 ore
    if (request.isFastDelivery) {
        expiresAt = new Date(now.getTime() + 24 * 60 * 60 * 1000);
    } 
    // Se il fan ha indicato una data specifica
    else if (request.needByDate) {
        const needBy = new Date(request.needByDate);
        if (needBy.getTime() > now.getTime()) {
            expiresAt = needBy;
        }
    }

    // 1. Crea la Request
    const requestData = {
      ...request,
      status: RequestStatus.PENDING,
      createdAt: now.toISOString(),
      updatedAt: now.toISOString(),
      expiresAt: expiresAt.toISOString()
    };
    const docRef = await addDoc(collection(db, 'requests'), requestData);
    const requestId = docRef.id;

    // 2. Crea il Record di Pagamento (Simulato)
    const platformFee = 2.00; // Costo fisso servizio
    const talentEarnings = request.pricePaid;
    const totalAmount = talentEarnings + platformFee;

    await addDoc(collection(db, 'payments'), {
      requestId: requestId,
      fanId: request.fanId,
      talentId: request.talentId,
      amount: totalAmount,
      currency: 'EUR',
      status: 'captured', // Simuliamo pagamento immediato
      platformFee: platformFee,
      talentEarnings: talentEarnings,
      createdAt: new Date().toISOString(),
      providerPaymentId: `mock_pay_${Date.now()}`
    } as Omit<Payment, 'id'>);

    // 3. Log
    await logAction(request.fanId, 'create_request', `Creata richiesta video per ${request.pricePaid} EUR`, requestId);

    return requestId;
  } catch (e) {
    console.error("Errore creazione richiesta: ", e);
    throw e;
  }
};

export const getRequestsForUser = async (userId: string, role: UserRole): Promise<VideoRequest[]> => {
  try {
    const fieldToCheck = role === UserRole.FAN ? 'fanId' : 'talentId';
    // Nota: in produzione servirebbero indici composti o query separate per evitare scan
    const q = query(collection(db, 'requests'), where(fieldToCheck, '==', userId));
    const querySnapshot = await getDocs(q);

    const requests: VideoRequest[] = [];
    querySnapshot.forEach((doc) => {
      requests.push({ id: doc.id, ...doc.data() } as VideoRequest);
    });

    return requests.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  } catch (error) {
    console.error("Errore getRequestsForUser:", error);
    return [];
  }
};

export const updateRequestStatus = async (requestId: string, status: RequestStatus, videoUrl?: string, videoId?: string): Promise<void> => {
  const requestRef = doc(db, 'requests', requestId);
  const data: any = { status, updatedAt: new Date().toISOString() };

  if (videoUrl) {
    data.videoUrl = videoUrl;
  }
  if (videoId) {
    data.videoId = videoId;
  }

  await updateDoc(requestRef, data);

  // Log dell'azione
  if (auth.currentUser) {
    await logAction(auth.currentUser.uid, `update_status_${status.toLowerCase()}`, `Stato richiesta aggiornato a ${status}`, requestId);
  }
};

// Logica per Annullamento Utente (entro finestra 30 min)
export const cancelRequestByFan = async (requestId: string): Promise<boolean> => {
    const requestRef = doc(db, 'requests', requestId);
    const snap = await getDoc(requestRef);

    if (!snap.exists()) return false;
    const data = snap.data() as VideoRequest;

    // Get Admin Settings for window
    const settings = await getAdminSettings();
    const createdAt = new Date(data.createdAt).getTime();
    const now = new Date().getTime();
    const diffMinutes = (now - createdAt) / 1000 / 60;

    if (diffMinutes > settings.refundWindowMinutes) {
        throw new Error(`Tempo scaduto. Puoi annullare solo entro ${settings.refundWindowMinutes} minuti.`);
    }

    await updateDoc(requestRef, { 
        status: RequestStatus.CANCELED_BY_FAN,
        updatedAt: new Date().toISOString()
    });

    // In un sistema reale, qui attiveremmo il rimborso Stripe
    await logAction(auth.currentUser!.uid, 'cancel_request', `Ordine annullato dal fan`, requestId);
    return true;
};

export const rejectRequest = async (requestId: string): Promise<void> => {
