// Logica Risoluzione Disputa (Admin)
export const resolveDispute = async (requestId: string, decision: 'FAN_WINS' | 'TALENT_WINS', adminNoteFan?: string, adminNoteTalent?: string) => {
    const newStatus = decision === 'FAN_WINS' ? RequestStatus.CORRECTION_NEEDED : RequestStatus.COMPLETED;

    const requestRef = doc(db, 'requests', requestId);
    await updateDoc(requestRef, {
        status: newStatus,
        adminNoteFan: adminNoteFan || '',
        adminNoteTalent: adminNoteTalent || '',
        updatedAt: new Date().toISOString()
    });

    await logAction(auth.currentUser!.uid, 'resolve_dispute', `Disputa risolta. Decisione: ${decision}. Note Fan: ${adminNoteFan}, Note Talent: ${adminNoteTalent}`, requestId);
};

// Controllo Scadenze (Da chiamare periodicamente o all'accesso dashboard)
export const checkExpirations = async () => {
    // Questa funzione è pesante, in produzione va su Cloud Functions schedulate.
    // Qui la simuliamo client-side per l'MVP.

    const settings = await getAdminSettings();
    const now = new Date().getTime();

    // 1. Controlla ORDINI PENDING (Scadenza Consegna)
    const qPending = query(collection(db, 'requests'), where('status', '==', RequestStatus.PENDING));
    const snapPending = await getDocs(qPending);

    snapPending.forEach(async (docSnap) => {
        const req = docSnap.data() as VideoRequest;
        const created = new Date(req.createdAt).getTime();

        // Calcola deadline
        let deadlineTimestamp = 0;

        // Se abbiamo già calcolato e salvato expiresAt, usiamolo
        if (req.expiresAt) {
            deadlineTimestamp = new Date(req.expiresAt).getTime();
        } else {
            // Fallback calcolo al volo per vecchi ordini
            let deadlineDays = settings.deliveryDeadlineDays;
            if (req.isFastDelivery) deadlineDays = 1;
            deadlineTimestamp = created + (deadlineDays * 24 * 60 * 60 * 1000);
        }

        if (now > deadlineTimestamp) {
            console.log(`Richiesta ${docSnap.id} scaduta. Auto-rimborso.`);
            await updateDoc(docSnap.ref, {
                status: RequestStatus.EXPIRED,
                updatedAt: new Date().toISOString()
            });
        }
    });

    // 2. Controlla ORDINI IN_REVIEW (Auto-Completamento dopo 24h/48h)
    const qReview = query(collection(db, 'requests'), where('status', '==', RequestStatus.IN_REVIEW));
    const snapReview = await getDocs(qReview);

    snapReview.forEach(async (docSnap) => {
        const req = docSnap.data() as VideoRequest;
        // La data di inizio review è l'ultimo update (quando è stato caricato il video)
        const reviewStarted = new Date(req.updatedAt || req.createdAt).getTime();
        const diffHours = (now - reviewStarted) / (1000 * 60 * 60);

        if (diffHours > settings.disputeWindowHours) {
             console.log(`Richiesta ${docSnap.id} auto-completata dopo finestra contestazione.`);
             await updateDoc(docSnap.ref, {
                status: RequestStatus.COMPLETED,
                updatedAt: new Date().toISOString()
            });
        }
    });
};


// --- STORAGE & VIDEO METADATA ---

export const uploadVideo = async (file: Blob, requestId: string): Promise<string> => {
  if (!auth.currentUser) throw new Error("Utente non autenticato");

  // SAFETY CHECK
  const reqRef = doc(db, 'requests', requestId);
  const reqSnap = await getDoc(reqRef);

  if (reqSnap.exists()) {
      const requestData = reqSnap.data() as VideoRequest;
      if (requestData.status === RequestStatus.PENDING) {
        const settings = await getAdminSettings();
        const created = new Date(requestData.createdAt).getTime();
        const now = new Date().getTime();
        const diffMinutes = (now - created) / 1000 / 60;

        if (diffMinutes < settings.refundWindowMinutes) {
            const minsLeft = Math.ceil(settings.refundWindowMinutes - diffMinutes);
            throw new Error(`Non puoi ancora caricare il video. Il fan ha ancora ${minsLeft} minuti per annullare l'ordine.`);
        }
      }
  }

  // DETERMINE EXTENSION AND MIME TYPE DYNAMICALLY
  const mimeType = file.type || 'video/mp4';
  let extension = 'mp4';
  if (mimeType.includes('webm')) extension = 'webm';
  else if (mimeType.includes('quicktime')) extension = 'mov';

  const fileName = `response_${Date.now()}.${extension}`;
  const storageRef = ref(storage, `videos/${requestId}/${fileName}`);
  const metadata = { contentType: mimeType };

  console.log(`Inizio upload reale su Firebase Storage: videos/${requestId}/${fileName} (${mimeType})`);

  // Upload reale
  const snapshot = await uploadBytes(storageRef, file, metadata);
  const downloadURL = await getDownloadURL(storageRef);

  // Creazione record nella collezione 'videos' (Metadata)
  const videoDocRef = await addDoc(collection(db, 'videos'), {
    requestId: requestId,
    talentId: auth.currentUser.uid,
    url: downloadURL,
    format: mimeType,
    sizeBytes: snapshot.metadata.size,
    createdAt: new Date().toISOString(),
    views: 0
  } as Omit<VideoMetadata, 'id'>);

  console.log("Metadati video salvati con ID:", videoDocRef.id);

  await updateRequestStatus(requestId, RequestStatus.IN_REVIEW, downloadURL, videoDocRef.id);

  return downloadURL;
};

export const deleteVideoFromRequest = async (requestId: string): Promise<void> => {
    const requestRef = doc(db, 'requests', requestId);
    const snap = await getDoc(requestRef);
    if (!snap.exists()) throw new Error("Richiesta non trovata");

    const data = snap.data() as VideoRequest;

    if (data.status === RequestStatus.COMPLETED) {
        throw new Error("Impossibile eliminare un video di un ordine completato.");
    }

    const newStatus = data.status === RequestStatus.CORRECTION_NEEDED ? RequestStatus.CORRECTION_NEEDED : RequestStatus.PENDING;

    await updateDoc(requestRef, {
        videoUrl: deleteField(),
        videoId: deleteField(),
        status: newStatus,
        updatedAt: new Date().toISOString()
    });

    if (auth.currentUser) {
        await logAction(auth.currentUser.uid, 'delete_video', `Video eliminato dal talent. Stato ritornato a ${newStatus}`, requestId);
    }
};

export const uploadAvatar = async (file: Blob, userId: string): Promise<string> => {
    const fileName = `avatar_${Date.now()}.jpg`;
    const storageRef = ref(storage, `avatars/${userId}/${fileName}`);
    const metadata = { contentType: 'image/jpeg' };

    console.log("Upload avatar...");
    await uploadBytes(storageRef, file, metadata);
    const downloadURL = await getDownloadURL(storageRef);

    // Aggiorna user doc
    const userRef = doc(db, 'users', userId);
    await updateDoc(userRef, { avatarUrl: downloadURL });

    return downloadURL;
};

// --- CHAT SYSTEM ---

// Invia un messaggio (Utente -> Admin o Admin -> Utente)
export const sendMessage = async (
  conversationId: string, // ID Conversazione (di solito userId del fan/talent)
  senderId: string,
  text: string,
  isAdmin: boolean
) => {
    if (!text.trim()) return;

    const conversationRef = doc(db, 'conversations', conversationId);
    const messagesCollection = collection(conversationRef, 'messages');

    // 1. Aggiungi il messaggio alla sottocollezione
    await addDoc(messagesCollection, {
        senderId,
        text,
        timestamp: serverTimestamp(),
        isAdmin,
        isEdited: false
    });

    // 2. Aggiorna i metadati della conversazione
    // Se la conversazione non esiste ancora (primo messaggio), dobbiamo crearla
    // Questo succede se è l'utente a scrivere il primo messaggio
    const conversationSnap = await getDoc(conversationRef);

    if (!conversationSnap.exists()) {
        // Recupera info utente per popolare la conversazione
        // (Assumiamo che se non esiste, è perché l'utente sta scrivendo per la prima volta)
        const userRef = doc(db, 'users', conversationId);
        const userSnap = await getDoc(userRef);
        const userData = userSnap.data() as User;

        await setDoc(conversationRef, {
            userId: conversationId,
            userName: userData?.name || 'Utente',
            userRole: userData?.role || UserRole.FAN,
            userAvatar: userData?.avatarUrl || '',
            lastMessage: text,
            lastMessageAt: serverTimestamp(),
            unreadCountAdmin: isAdmin ? 0 : 1, // Se scrive l'utente, admin ha 1 non letto
            unreadCountUser: isAdmin ? 1 : 0
        });
    } else {
        // Conversazione esiste, aggiorna contatori e ultimo messaggio
        await updateDoc(conversationRef, {
            lastMessage: text,
            lastMessageAt: serverTimestamp(),
            unreadCountAdmin: isAdmin ? 0 : increment(1), // Se non sono admin, incremento contatore admin
            unreadCountUser: isAdmin ? increment(1) : 0   // Se sono admin, incremento contatore utente
        });
    }
};

// Modifica un messaggio esistente
export const updateChatMessage = async (conversationId: string, messageId: string, newText: string) => {
    const msgRef = doc(db, 'conversations', conversationId, 'messages', messageId);
    await updateDoc(msgRef, {
        text: newText,
        isEdited: true
    });
};

// Elimina un messaggio
export const deleteChatMessage = async (conversationId: string, messageId: string) => {
    const msgRef = doc(db, 'conversations', conversationId, 'messages', messageId);
    await deleteDoc(msgRef);
};

// Segna come letti i messaggi (azzera contatore)
export const markConversationAsRead = async (conversationId: string, role: UserRole) => {
    const conversationRef = doc(db, 'conversations', conversationId);

    if (role === UserRole.ADMIN) {
        await updateDoc(conversationRef, { unreadCountAdmin: 0 });
    } else {
        await updateDoc(conversationRef, { unreadCountUser: 0 });
    }
};

// Listener per i messaggi di una specifica conversazione
export const subscribeToMessages = (conversationId: string, callback: (msgs: ChatMessage[]) => void) => {
    const messagesRef = collection(db, 'conversations', conversationId, 'messages');
    const q = query(messagesRef, orderBy('timestamp', 'asc'));

    return onSnapshot(q, (snapshot) => {
        const messages: ChatMessage[] = [];
        snapshot.forEach(doc => {
            const data = doc.data();
            messages.push({
                id: doc.id,
                ...data,
                timestamp: data.timestamp // keep raw timestamp for sorting logic in UI if needed
            } as ChatMessage);
        });
        callback(messages);
    });
};

// Listener per la lista delle conversazioni (Lato Admin)
export const subscribeToConversations = (callback: (convs: Conversation[]) => void) => {
    const conversationsRef = collection(db, 'conversations');
    const q = query(conversationsRef, orderBy('lastMessageAt', 'desc'));

    return onSnapshot(q, (snapshot) => {
        const conversations: Conversation[] = [];
        snapshot.forEach(doc => {
            const data = doc.data();
            conversations.push({
                id: doc.id,
                ...data
            } as Conversation);
        });
        callback(conversations);
    });
};

