/**
 * Servizio per il processing video lato client.
 * Aggiunge una filigrana (watermark) sovraimpressa permanentemente al video.
 */

export const addWatermarkToVideo = async (videoFile: File, watermarkUrl: string): Promise<{ blob: Blob, extension: string }> => {
    return new Promise(async (resolve, reject) => {
        try {
            // Helper per caricare immagine in modo sicuro (supporta Data URI e CORS)
            const loadImg = (url: string): Promise<HTMLImageElement> => {
                return new Promise((res, rej) => {
                    const img = new Image();
                    img.crossOrigin = 'anonymous'; // Essenziale per non "sporcare" il canvas
                    img.onload = () => res(img);
                    img.onerror = (e) => rej(new Error(`Errore caricamento immagine watermark: ${e}`));
                    img.src = url;
                });
            };

            // 1. Carica l'immagine Watermark
            const wmImg = await loadImg(watermarkUrl);

            // 2. Prepara l'elemento Video (nascosto)
            const video = document.createElement('video');
            video.playsInline = true;
            // IMPORTANTE: muted=false per permettere all'AudioContext di catturare l'audio.
            // Il suono non si sentirà perché lo reindirizziamo nel context senza collegarlo a destination.
            video.muted = false; 
            video.src = URL.createObjectURL(videoFile);
            video.style.display = 'none';
            document.body.appendChild(video);

            await new Promise((res, rej) => {
                video.onloadeddata = () => res(true);
                video.onerror = (e) => rej(new Error("Errore caricamento video source"));
            });

            // 3. Prepara Canvas e Context
            const canvas = document.createElement('canvas');
            canvas.width = video.videoWidth;
            canvas.height = video.videoHeight;
            const ctx = canvas.getContext('2d');

            if (!ctx) {
                document.body.removeChild(video);
                throw new Error("Impossibile inizializzare Canvas 2D");
            }

            // 4. Setup Audio Context
            // Safari richiede webkitAudioContext
            const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
            const audioCtx = new AudioContext();

            // Crea sorgente dall'elemento video. 
            // Questo "scollega" l'audio dagli speaker e lo porta nel grafo web audio.
            const source = audioCtx.createMediaElementSource(video);
            const dest = audioCtx.createMediaStreamDestination();
            source.connect(dest);
            // NON collegare a audioCtx.destination per evitare echo

            // 5. Determina Formato Supportato
            let mimeType = '';
            let extension = '';
            const types = [
                'video/mp4',             // Safari 14.5+ (H.264/AAC)
                'video/webm;codecs=vp9', // Chrome High Quality
                'video/webm;codecs=vp8', // Chrome Standard
                'video/webm'             // Fallback
            ];

            for (const t of types) {
                if (MediaRecorder.isTypeSupported(t)) {
                    mimeType = t;
                    extension = t.includes('mp4') ? 'mp4' : 'webm';
                    break;
                }
            }

            if (!mimeType) {
                audioCtx.close();
                document.body.removeChild(video);
                throw new Error("Il tuo browser non supporta la registrazione video.");
            }

            console.log(`Processing video con mimeType: ${mimeType}`);

            // 6. Crea Stream Combinato (Video da Canvas + Audio da Context)
            // Fallback per captureStream
            const streamFn = (canvas as any).captureStream || (canvas as any).webkitCaptureStream;
            if (!streamFn) {
                 audioCtx.close();
                 document.body.removeChild(video);
                 throw new Error("Canvas captureStream non supportato.");
            }

            const canvasStream = streamFn.call(canvas, 30); // 30 FPS target
            const combinedStream = new MediaStream([
                ...canvasStream.getVideoTracks(),
                ...dest.stream.getAudioTracks()
            ]);

            const recorder = new MediaRecorder(combinedStream, { 
                mimeType,
                videoBitsPerSecond: 2500000 // 2.5 Mbps target quality
            });

            const chunks: Blob[] = [];
            recorder.ondataavailable = (e) => {
                if (e.data.size > 0) chunks.push(e.data);
            };

            recorder.onstop = () => {
                const finalBlob = new Blob(chunks, { type: mimeType });

                // Cleanup
                audioCtx.close();
                document.body.removeChild(video);
                URL.revokeObjectURL(video.src);

                resolve({ blob: finalBlob, extension });
            };

            recorder.onerror = (e) => {
                audioCtx.close();
                document.body.removeChild(video);
                reject(e);
            };

            // 7. Loop di Disegno
            const draw = () => {
                if (video.paused || video.ended) return;

                // Disegna frame video
                ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

                // Calcolo dimensioni Watermark (Clamp logic)
                const scaleReference = 1280;
                const scaleFactor = canvas.width / scaleReference;

                const minW = 100 * scaleFactor;
                const maxW = 300 * scaleFactor;
                const oneThirdW = canvas.width * 0.33;

                // Clamp width: min(maxW, max(minW, oneThirdW))
                let w = Math.max(minW, Math.min(oneThirdW, maxW));

                // Mantieni aspect ratio immagine
                const ratio = wmImg.width / wmImg.height;
                let h = w / ratio;

                const padding = 20 * scaleFactor; // Padding dal bordo
                const x = canvas.width - w - padding;
                const y = canvas.height - h - padding;

                ctx.globalAlpha = 0.9; // Leggera trasparenza
                ctx.drawImage(wmImg, x, y, w, h);
                ctx.globalAlpha = 1.0;

                requestAnimationFrame(draw);
            };

            // Avvia tutto
            recorder.start();
            video.play().then(() => {
                draw();
            }).catch(e => {
                console.error("Errore play video:", e);
                reject(e);
            });

            video.onended = () => {
                recorder.stop();
            };

        } catch (error) {
            console.error("Errore setup video processing:", error);
            reject(error);
        }
    });
};

