/**
 * Servizio per il processing video lato client.
 * Aggiunge una filigrana (watermark) sovraimpressa permanentemente al video.
 */

export const addWatermarkToVideo = async (videoFile: File, watermarkUrl: string): Promise<{ blob: Blob, extension: string }> => {
    return new Promise(async (resolve, reject) => {
        let video: HTMLVideoElement | null = null;
        let audioCtx: AudioContext | null = null;
        let objectUrlToRevoke: string | null = null;

        try {
            // Helper per caricare immagine in modo sicuro
            const loadImg = async (url: string): Promise<HTMLImageElement> => {
                // TENTATIVO 1: Fetch come Blob (più robusto per CORS)
                // Se l'URL è http/https, proviamo a scaricarlo come blob locale.
                // Questo evita problemi di "Tainted Canvas" se il server supporta CORS ma la cache browser fa i capricci.
                if (url.startsWith('http')) {
                    try {
                        const response = await fetch(url, { mode: 'cors' });
                        if (response.ok) {
                            const blob = await response.blob();
                            const blobUrl = URL.createObjectURL(blob);
                            objectUrlToRevoke = blobUrl; // Segna per cleanup
                            return await loadImgAsElement(blobUrl, false); // false = no crossOrigin needed for blob:
                        }
                    } catch (e) {
                        console.warn("Fetch watermark fallito, tento caricamento standard Image...", e);
                    }
                }

                // TENTATIVO 2 (o fallback): Caricamento standard Image
                const needCors = !url.startsWith('data:') && !url.startsWith('blob:');
                return await loadImgAsElement(url, needCors);
            };

            const loadImgAsElement = (src: string, useCors: boolean): Promise<HTMLImageElement> => {
                return new Promise((res, rej) => {
                    const img = new Image();
                    if (useCors) {
                        img.crossOrigin = 'anonymous';
                    }
                    img.onload = () => res(img);
                    img.onerror = (e) => rej(new Error(`Impossibile caricare immagine filigrana.`));
                    img.src = src;
                });
            };

            console.log("Inizio processing video...");

            // 1. Carica l'immagine Watermark
            const wmImg = await loadImg(watermarkUrl);

            // 2. Prepara l'elemento Video (nascosto)
            video = document.createElement('video');
            video.playsInline = true;
            video.muted = false; // Necessario per catturare audio
            video.src = URL.createObjectURL(videoFile);
            video.style.display = 'none';
            document.body.appendChild(video);

            // Attendi caricamento metadati per dimensioni
            await new Promise((res, rej) => {
                video!.onloadedmetadata = () => res(true);
                video!.onerror = () => rej(new Error("Il file video sembra danneggiato o formato non supportato."));
            });

            // 3. Calcolo Risoluzione Ottimizzata (Max 1280px)
            // Video 4K mandano in crash i browser mobile su Canvas. Ridimensioniamo a HD.
            const MAX_DIMENSION = 1280;
            let width = video.videoWidth;
            let height = video.videoHeight;

            if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
                const ratio = width / height;
                if (width > height) {
                    width = MAX_DIMENSION;
                    height = width / ratio;
                } else {
                    height = MAX_DIMENSION;
                    width = height * ratio;
                }
                console.log(`Video ridimensionato a ${Math.round(width)}x${Math.round(height)} per performance.`);
            }

            // 4. Prepara Canvas
            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d', { alpha: false }); // alpha false per performance

            if (!ctx) throw new Error("Impossibile inizializzare Canvas 2D (Memoria insufficiente?)");

            // 5. Setup Audio Context
            const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
            audioCtx = new AudioContext();

            // Resume context se sospeso (policy browser)
            if (audioCtx.state === 'suspended') {
                await audioCtx.resume();
            }

            const source = audioCtx.createMediaElementSource(video);
            const dest = audioCtx.createMediaStreamDestination();
            source.connect(dest);

            // 6. Determina Formato Output
            let mimeType = '';
            let extension = '';
            // Ordine di preferenza browser
            const types = [
                'video/mp4',             // Safari
                'video/webm;codecs=vp9', // Chrome High Quality
                'video/webm;codecs=vp8', // Chrome Standard
                'video/webm'             // Fallback
            ];

            for (const t of types) {
                if (MediaRecorder.isTypeSupported(t)) {
                    mimeType = t;
                    extension = t.includes('mp4') ? 'mp4' : 'webm';
                    break;
                }
            }

            if (!mimeType) throw new Error("Il tuo browser non supporta la registrazione video (MediaRecorder).");

            // 7. Stream Combinato
            const streamFn = (canvas as any).captureStream || (canvas as any).webkitCaptureStream;
            if (!streamFn) throw new Error("Canvas captureStream non supportato.");

            const canvasStream = streamFn.call(canvas, 30); // 30 FPS

            // Gestione tracce audio: se il video originale non ha audio, non aggiungere traccia vuota che potrebbe rompere
            const audioTracks = dest.stream.getAudioTracks();
            const tracks = [...canvasStream.getVideoTracks()];
            if (audioTracks.length > 0) {
                tracks.push(...audioTracks);
            }

            const combinedStream = new MediaStream(tracks);

            const recorder = new MediaRecorder(combinedStream, { 
                mimeType,
                videoBitsPerSecond: 2500000 // 2.5 Mbps
            });

            const chunks: Blob[] = [];
            recorder.ondataavailable = (e) => {
                if (e.data.size > 0) chunks.push(e.data);
            };

            recorder.onstop = () => {
                const finalBlob = new Blob(chunks, { type: mimeType });

                // Cleanup
                if (audioCtx) audioCtx.close();
                if (video) {
                    document.body.removeChild(video);
                    URL.revokeObjectURL(video.src);
                }
                if (objectUrlToRevoke) {
                    URL.revokeObjectURL(objectUrlToRevoke);
                }

                resolve({ blob: finalBlob, extension });
            };

            recorder.onerror = (e) => {
                console.error("Recorder error:", e);
                // Non rejectiamo qui, lasciamo che onstop gestisca o il try/catch esterno
            };

            // 8. Loop Disegno
            const draw = () => {
                if (!video || video.paused || video.ended) return;

                // Disegna video ridimensionato
                ctx.drawImage(video, 0, 0, width, height);

                // Disegna Watermark
                // Logica Clamp: Min 100px, Max 300px (scalati), oppure 33% larghezza
                const scaleReference = 1280;
                const scaleFactor = width / scaleReference;

                const minW = 100 * scaleFactor;
                const maxW = 300 * scaleFactor;
                const oneThirdW = width * 0.33;

                let w = Math.max(minW, Math.min(oneThirdW, maxW));
                const ratio = wmImg.width / wmImg.height;
                let h = w / ratio;

                const padding = 20 * scaleFactor;
                const x = width - w - padding;
                const y = height - h - padding;

                ctx.globalAlpha = 0.9;
                ctx.drawImage(wmImg, x, y, w, h);
                ctx.globalAlpha = 1.0;

                requestAnimationFrame(draw);
            };

            // Avvio
            recorder.start();
            await video.play();
            draw();

            video.onended = () => {
                recorder.stop();
            };

        } catch (error) {
            console.error("Errore critico processing video:", error);
            // Cleanup in caso di errore
            if (audioCtx) audioCtx.close();
            if (video && video.parentNode) {
                document.body.removeChild(video);
            }
            if (objectUrlToRevoke) {
                URL.revokeObjectURL(objectUrlToRevoke);
            }
            reject(error);
        }
    });
};

import React, { useEffect, useState, useRef } from 'react';
import { User, UserRole, VideoRequest, RequestStatus, AdminSettings } from '../types';
import { getRequestsForUser, uploadVideo, upgradeUserToTalent, createRequest, cancelRequestByFan, openDispute, completeOrder, checkExpirations, getAdminSettings, rejectRequest, deleteVideoFromRequest } from '../services/dataService';
import { addWatermarkToVideo } from '../services/videoUtils';
import VideoPlayer from '../components/VideoPlayer';
import { Clock, CheckCircle, XCircle, Video as VideoIcon, Upload, Loader2, Camera, StopCircle, RefreshCw, Wallet, DollarSign, TrendingUp, CreditCard, Wrench, AlertTriangle, Lock, CalendarClock, Info, Hourglass, Lightbulb, Trash2 } from 'lucide-react';
import confetti from 'canvas-confetti';

interface DashboardProps {
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<'requests' | 'wallet'>('requests');
  const [requests, setRequests] = useState<VideoRequest[]>([]);
  const [loading, setLoading] = useState(true);

  // Admin Settings (for time windows)
  const [adminSettings, setAdminSettings] = useState<AdminSettings | null>(null);

  // States for Talent Workflow
  const [selectedRequest, setSelectedRequest] = useState<VideoRequest | null>(null);

  // Upload Mode State
  const [uploadMode, setUploadMode] = useState<'upload' | 'record'>('upload');
  const [uploadFile, setUploadFile] = useState<File | null>(null);

  // Recording Mode State
  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordedChunks, setRecordedChunks] = useState<Blob[]>([]);
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);

  // General Workflow State
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [processingStatus, setProcessingStatus] = useState<string>('');

  // Dispute Modal State
  const [disputeModalOpen, setDisputeModalOpen] = useState(false);
  const [disputeReason, setDisputeReason] = useState('');
  const [requestToDispute, setRequestToDispute] = useState<VideoRequest | null>(null);

  // Wallet Mock Data
  const [walletData] = useState({
    balance: 185.00,
    pending: 450.00,
    totalEarned: 1250.00,
    nextPayout: '15 Ottobre'
  });

  const refreshData = async () => {
    setLoading(true);
    try {
        // Run checks
        await checkExpirations();

        const [data, settings] = await Promise.all([
            getRequestsForUser(user.id, user.role),
            getAdminSettings()
        ]);
        setRequests(data);
        setAdminSettings(settings);
    } catch (e) {
        console.error("Errore fetch richieste", e);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => {
    refreshData();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  // Cleanup stream on unmount or modal close
  useEffect(() => {
    return () => {
      stopCamera();
    };
  }, []);

  // --- LOGICA TEMPISTICA UNIFICATA ---

  const getRefundState = (req: VideoRequest) => {
      const windowMinutes = adminSettings?.refundWindowMinutes || 30;
      const created = new Date(req.createdAt).getTime();
      const now = new Date().getTime();
      const diffMins = (now - created) / 1000 / 60;
      const isActive = diffMins < windowMinutes;
      const minsLeft = Math.max(0, Math.ceil(windowMinutes - diffMins));
      return { isActive, minsLeft };
  };

  const getDisputeTimeLeft = (req: VideoRequest) => {
      const windowHours = adminSettings?.disputeWindowHours || 48;
      const updated = new Date(req.updatedAt || req.createdAt).getTime();
      const now = new Date().getTime();
      const diffHours = (now - updated) / (1000 * 60 * 60);
      return Math.max(0, Math.ceil(windowHours - diffHours));
  };

  const getDeadlineCountdown = (req: VideoRequest) => {
    if (!req.expiresAt) return null;
    const expires = new Date(req.expiresAt).getTime();
    const now = new Date().getTime();
    const diffMs = expires - now;
    if (diffMs <= 0) return "SCADUTO";
    const days = Math.floor(diffMs / (1000 * 60 * 60 * 24));
    const hours = Math.floor((diffMs % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    const minutes = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
    if (days > 0) return `${days}g ${hours}h`;
    return `${hours}h ${minutes}m`;
  };

  const getUrgencyColor = (req: VideoRequest) => {
    if (!req.expiresAt) return "bg-gray-100 text-gray-800";
    const expires = new Date(req.expiresAt).getTime();
    const now = new Date().getTime();
    const diffHours = (expires - now) / (1000 * 60 * 60);
    if (diffHours < 0) return "bg-gray-200 text-gray-600";
    if (diffHours < 24) return "bg-red-100 text-red-800 border border-red-200 animate-pulse";
    if (diffHours < 72) return "bg-amber-100 text-amber-800 border border-amber-200";
    return "bg-emerald-100 text-emerald-800 border border-emerald-200";
  };

  // --- ACTIONS ---

  const handleCancelOrder = async (requestId: string) => {
      if(!confirm("Sei sicuro di voler annullare l'ordine? Questa azione è irreversibile.")) return;
      try {
          await cancelRequestByFan(requestId);
          alert("Ordine annullato e rimborsato correttamente.");
          refreshData();
      } catch (e: any) {
          alert(e.message || "Errore durante l'annullamento.");
      }
  };

  const handleCompleteOrder = async (req: VideoRequest) => {
      try {
          await completeOrder(req.id);
          confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
          refreshData();
      } catch (e) {
          console.error(e);
          alert("Errore completamento ordine.");
      }
  };

  const handleOpenDisputeModal = (req: VideoRequest) => {
      setRequestToDispute(req);
      setDisputeReason('');
      setDisputeModalOpen(true);
  };

  const submitDispute = async () => {
      if (!requestToDispute || !disputeReason.trim()) return;
      try {
          await openDispute(requestToDispute.id, disputeReason);
          setDisputeModalOpen(false);
          refreshData();
          alert("Contestazione aperta. L'admin esaminerà la richiesta.");
      } catch (e) {
          console.error(e);
          alert("Errore apertura contestazione.");
      }
  };

  const handleRejectRequest = async (requestId: string) => {
      if(!confirm("Sei sicuro di voler rifiutare questa richiesta? L'importo verrà rimborsato al fan.")) return;
      setLoading(true);
      try {
          await rejectRequest(requestId);
          alert("Richiesta rifiutata con successo.");
          refreshData();
      } catch (e) {
          console.error(e);
          alert("Errore durante il rifiuto.");
      } finally {
          setLoading(false);
      }
  };

  const handleDeleteVideo = async (req: VideoRequest) => {
      if(!confirm("Sei sicuro di voler eliminare questo video? La richiesta tornerà in stato 'In attesa'.")) return;
      setLoading(true);
      try {
          await deleteVideoFromRequest(req.id);
          await refreshData();
          alert("Video eliminato.");
      } catch (e: any) {
          console.error(e);
          alert(e.message || "Errore durante l'eliminazione.");
      } finally {
          setLoading(false);
      }
  };

  // --- DEVELOPER ACTIONS ---
  const handleBecomeTalent = async () => {
    if (!confirm("Vuoi trasformare questo account in un profilo Talent?")) return;
    setLoading(true);
    try {
        await upgradeUserToTalent(user.id);
        alert("Profilo aggiornato! Ricarica la pagina.");
        window.location.reload();
    } catch (e) {
        console.error(e);
        alert("Errore aggiornamento profilo.");
    } finally {
        setLoading(false);
    }
  };

  const handleCreateTestRequest = async () => {
    setLoading(true);
    try {
        await createRequest({
            talentId: user.id,
            fanId: user.id,
            fanName: "Test User",
            recipientName: "Me Stesso (Test)",
            instructions: "Test tecnico video upload.",
            occasion: "Test Tecnico",
            pricePaid: 0
        });
        await refreshData();
        alert("Richiesta di test creata!");
    } catch (e) {
        console.error(e);
        alert("Errore creazione richiesta test.");
    } finally {
        setLoading(false);
    }
  };

  // --- RECORDING LOGIC ---

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
      alert("Impossibile accedere alla videocamera. Verifica i permessi.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
  };

  const startRecording = () => {
    if (!stream) return;
    setRecordedChunks([]);
    const mediaRecorder = new MediaRecorder(stream);
    mediaRecorderRef.current = mediaRecorder;
    mediaRecorder.ondataavailable = (event) => {
      if (event.data.size > 0) setRecordedChunks((prev) => [...prev, event.data]);
    };
    mediaRecorder.start();
    setIsRecording(true);
    setRecordingTime(0);
    const interval = setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    mediaRecorder.onstop = () => {
        clearInterval(interval);
        setIsRecording(false);
    };
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
    }
  };

  useEffect(() => {
    if (!isRecording && recordedChunks.length > 0) {
      const blob = new Blob(recordedChunks, { type: 'video/webm' });
      setRecordedBlob(blob);
      const url = URL.createObjectURL(blob);
      setPreviewUrl(url);
      stopCamera();
    }
  }, [isRecording, recordedChunks]);

  const resetRecording = () => {
    setRecordedBlob(null);
    setPreviewUrl(null);
    setRecordedChunks([]);
    setRecordingTime(0);
    startCamera();
  };

  // --- SUBMISSION LOGIC (Updated with Watermark Processing) ---

  const handleSubmit = async () => {
    if (!selectedRequest) return;

    let rawFile: Blob | null = uploadMode === 'upload' ? uploadFile : recordedBlob;
    if (!rawFile) return;

    setIsSubmitting(true);
    setProcessingStatus('Preparazione video...');

    try {
        let finalFile = rawFile;
        // Default extension se non processato (es. video originale caricato)
        let finalType = rawFile.type || 'video/mp4'; 

        // 1. Processing Watermark
        // Tentiamo SEMPRE se c'è un URL. Se fallisce, usiamo fallback.
        if (adminSettings?.watermarkUrl) {
            setProcessingStatus('Applicazione filigrana in corso (potrebbe richiedere qualche secondo)...');
            try {
                // Convert Blob to File if needed for consistency
                const fileObj = rawFile instanceof File ? rawFile : new File([rawFile], "recorded.webm", { type: rawFile.type || 'video/webm' });

                // Chiama la funzione di processing
                const result = await addWatermarkToVideo(fileObj, adminSettings.watermarkUrl);
                finalFile = result.blob;
                // Imposta il mime type corretto in base a ciò che ha prodotto il recorder (es. video/mp4)
                finalType = result.extension === 'mp4' ? 'video/mp4' : 'video/webm';

                console.log("Watermark applicato correttamente.");
            } catch (err: any) {
                console.error("Errore applicazione watermark:", err);
                // FALLBACK SILENZIOSO:
                // Procediamo con il video originale e mostriamo status ma non blocchiamo.
                setProcessingStatus('Filigrana non applicata (errore tecnico). Caricamento originale...');
                await new Promise(r => setTimeout(r, 1000)); // Breve pausa per far leggere lo stato
            }
        }

        // 2. Upload
        setProcessingStatus('Caricamento su server...');

        // Per uploadVideo, possiamo passare un blob con type forzato
        // Creiamo un nuovo blob con il type corretto se necessario
        const uploadBlob = finalFile.slice(0, finalFile.size, finalType);

        await uploadVideo(uploadBlob, selectedRequest.id);

        closeModal();
        refreshData();
    } catch (error: any) {
        console.error("Errore upload:", error);
        alert(error.message || "Errore durante il caricamento del video.");
    } finally {
        setIsSubmitting(false);
        setProcessingStatus('');
    }
  };

  const closeModal = () => {
    setSelectedRequest(null);
    setUploadFile(null);
    setRecordedBlob(null);
    setPreviewUrl(null);
    setRecordedChunks([]);
    setIsSubmitting(false);
    setProcessingStatus('');
    stopCamera();
  };

  const openModal = (req: VideoRequest) => {
      setSelectedRequest(req);
      setUploadMode('upload');
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getStatusBadge = (status: RequestStatus) => {
    switch(status) {
        case RequestStatus.PENDING: return <span className="bg-amber-100 text-amber-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-amber-200"><Clock className="w-3 h-3 mr-1"/> In attesa</span>;
        case RequestStatus.IN_REVIEW: return <span className="bg-blue-100 text-blue-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-blue-200"><Hourglass className="w-3 h-3 mr-1"/> Revisione Fan</span>;
