        case RequestStatus.DISPUTE_OPEN: return <span className="bg-red-100 text-red-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-red-200"><AlertTriangle className="w-3 h-3 mr-1"/> Contestazione</span>;
        case RequestStatus.CORRECTION_NEEDED: return <span className="bg-orange-100 text-orange-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-orange-200"><RefreshCw className="w-3 h-3 mr-1"/> Correzione Richiesta</span>;
        case RequestStatus.EXPIRED: return <span className="bg-gray-200 text-gray-600 text-xs px-2 py-1 rounded-full flex items-center w-fit"><Clock className="w-3 h-3 mr-1"/> Scaduto</span>;
        case RequestStatus.CANCELED_BY_FAN: return <span className="bg-gray-200 text-gray-600 text-xs px-2 py-1 rounded-full flex items-center w-fit"><XCircle className="w-3 h-3 mr-1"/> Annullato</span>;
        default: return <span className="bg-gray-100 text-gray-800 text-xs px-2 py-1 rounded-full">{status}</span>;
    }
  };

  if (loading) return <div className="flex justify-center p-12"><Loader2 className="animate-spin text-slate-900 h-8 w-8" /></div>;

  return (
