            <button 
                onClick={refreshData}
                className="bg-white border border-gray-200 text-gray-700 hover:bg-gray-50 hover:text-slate-900 px-4 py-2 rounded-lg text-sm font-medium shadow-sm transition-all flex items-center justify-center"
                title="Ricarica i dati della dashboard"
            >
                <RefreshCw className="w-4 h-4 mr-2" />
                Aggiorna
            </button>

            {user.role === UserRole.TALENT && (
            <div className="flex space-x-2 bg-white p-1 rounded-lg border border-gray-200 shadow-sm ml-auto md:ml-0">
                <button 
                onClick={() => setActiveTab('requests')}
                className={`px-4 py-2 rounded-md text-sm font-medium transition-colors flex items-center ${activeTab === 'requests' ? 'bg-slate-900 text-white shadow-md' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                <VideoIcon className="w-4 h-4 mr-2"/> <span className="hidden sm:inline">Richieste</span>
                </button>
                <button 
                onClick={() => setActiveTab('wallet')}
