             <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                <div className="flex items-center justify-between mb-2">
                   <h3 className="text-sm font-medium text-gray-500">Saldo Disponibile</h3>
                   <DollarSign className="w-5 h-5 text-emerald-600 bg-emerald-100 rounded-full p-1"/>
