/**
 * Servizio per il processing video lato client.
 * Aggiunge una filigrana (watermark) sovraimpressa permanentemente al video.
 */

export const addWatermarkToVideo = async (videoFile: File, watermarkUrl: string): Promise<{ blob: Blob, extension: string }> => {
    return new Promise(async (resolve, reject) => {
        let video: HTMLVideoElement | null = null;
        let audioCtx: AudioContext | null = null;
        let objectUrlToRevoke: string | null = null;
        let cleanupDone = false;
        let timeoutId: any = null;

        // Funzione di cleanup sicura da chiamare una sola volta
        const cleanup = () => {
            if (cleanupDone) return;
            cleanupDone = true;
            console.log("Esecuzione cleanup video utils...");

            if (timeoutId) clearTimeout(timeoutId);

            if (audioCtx) {
                try { audioCtx.close(); } catch(e) {}
            }
            if (video) {
                video.pause();
                video.src = "";
                video.load();
                if (video.parentNode) {
                    document.body.removeChild(video);
                }
            }
            if (objectUrlToRevoke) {
                URL.revokeObjectURL(objectUrlToRevoke);
            }
        };

        // Timeout di sicurezza (30 secondi max per il processing)
        timeoutId = setTimeout(() => {
            cleanup();
            reject(new Error("Timeout: Il processo ha impiegato troppo tempo."));
        }, 30000);

        try {
            // Helper per caricare immagine in modo sicuro
            const loadImg = async (url: string): Promise<HTMLImageElement> => {
                // TENTATIVO 1: Fetch come Blob (più robusto per CORS su HTTP)
                if (url.startsWith('http')) {
                    try {
                        const response = await fetch(url, { mode: 'cors' });
                        if (response.ok) {
                            const blob = await response.blob();
                            const blobUrl = URL.createObjectURL(blob);
                            objectUrlToRevoke = blobUrl; 
                            return await loadImgAsElement(blobUrl, false); 
                        }
                    } catch (e) {
                        console.warn("Fetch watermark fallito, tento caricamento standard Image...", e);
                    }
                }

                // TENTATIVO 2 (Data URI o Fallback HTTP)
                const needCors = !url.startsWith('data:') && !url.startsWith('blob:');
                return await loadImgAsElement(url, needCors);
            };

            const loadImgAsElement = (src: string, useCors: boolean): Promise<HTMLImageElement> => {
                return new Promise((res, rej) => {
                    const img = new Image();
                    if (useCors) {
                        img.crossOrigin = 'anonymous';
                    }
                    img.onload = () => res(img);
                    img.onerror = (e) => rej(new Error(`Impossibile caricare file immagine.`));
                    img.src = src;
                });
            };

            console.log("Inizio processing video...");

            // 1. Carica l'immagine Watermark
            const wmImg = await loadImg(watermarkUrl);

            // 2. Prepara l'elemento Video
            // USARE POSIZIONAMENTO OFF-SCREEN (più sicuro di display:none o opacity)
            video = document.createElement('video');
            video.playsInline = true;
            video.preload = 'auto';
            video.muted = false; // Proviamo con audio attivo
            video.src = URL.createObjectURL(videoFile);

            // Stile per nasconderlo ma mantenerlo nel render tree
            video.style.position = 'fixed';
            video.style.top = '-10000px';
            video.style.left = '-10000px';
            video.style.width = '640px'; // Dimensione fissa per evitare layout thrashing iniziale
            video.style.height = '360px';
            video.style.zIndex = '-9999';
            video.style.visibility = 'visible'; // Importante per Safari

            document.body.appendChild(video);

            // Attendi caricamento metadati E canplay
            await new Promise((res, rej) => {
                let loaded = false;

                const onReady = () => {
                    if (!loaded) {
                        loaded = true;
                        res(true);
                    }
                };

                video!.onloadedmetadata = onReady;
                video!.oncanplay = onReady;
                video!.onerror = (e) => rej(new Error(`Errore caricamento video source: ${(e.target as any).error?.message}`));

                // Timeout caricamento source (5s)
                setTimeout(() => {
                    if (!loaded) rej(new Error("Timeout caricamento metadati video."));
                }, 5000);
            });

            // 3. Calcolo Risoluzione Ottimizzata (Max 720p/1280px per stabilità)
            const MAX_DIMENSION = 1280;
            let width = video.videoWidth;
            let height = video.videoHeight;

            if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
                const ratio = width / height;
                if (width > height) {
                    width = MAX_DIMENSION;
                    height = width / ratio;
                } else {
                    height = MAX_DIMENSION;
                    width = height * ratio;
                }
                console.log(`Video ridimensionato a ${Math.round(width)}x${Math.round(height)} per performance.`);
            }

            // 4. Prepara Canvas
            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d', { alpha: false }); 

            if (!ctx) throw new Error("Canvas 2D context null.");

            // 5. Setup Audio Context (Safe approach)
            // Se fallisce l'audio context, procediamo senza audio invece di bloccare tutto
            let source: MediaElementAudioSourceNode | null = null;
            let dest: MediaStreamAudioDestinationNode | null = null;

            try {
                const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
                if (AudioContext) {
                    audioCtx = new AudioContext();
                    if (audioCtx.state === 'suspended') {
                        await audioCtx.resume();
                    }
                    source = audioCtx.createMediaElementSource(video);
                    dest = audioCtx.createMediaStreamDestination();
                    source.connect(dest);
                }
            } catch (audioErr) {
                console.warn("AudioContext fallito, il video sarà muto:", audioErr);
            }

            // 6. Determina Formato Output
            let mimeType = '';
            let extension = '';

            const types = [
                'video/mp4',
                'video/webm;codecs=vp9',
                'video/webm;codecs=vp8',
                'video/webm'
            ];

            for (const t of types) {
                if (MediaRecorder.isTypeSupported(t)) {
                    mimeType = t;
                    extension = t.includes('mp4') ? 'mp4' : 'webm';
                    break;
                }
            }
            if (!mimeType) throw new Error("MediaRecorder non supportato dal browser.");

            // 7. Stream Combinato
            const streamFn = (canvas as any).captureStream || (canvas as any).webkitCaptureStream;
            if (!streamFn) throw new Error("Canvas captureStream non supportato.");

            const canvasStream = streamFn.call(canvas, 30); // 30 FPS

            const tracks = [...canvasStream.getVideoTracks()];

            // Aggiungi audio se disponibile
            if (dest) {
                const audioTracks = dest.stream.getAudioTracks();
                if (audioTracks.length > 0) {
                    tracks.push(...audioTracks);
                }
            }

            const combinedStream = new MediaStream(tracks);

            const recorder = new MediaRecorder(combinedStream, { 
                mimeType,
                videoBitsPerSecond: 2500000 // 2.5 Mbps target
            });

            const chunks: Blob[] = [];
            recorder.ondataavailable = (e) => {
                if (e.data.size > 0) chunks.push(e.data);
            };

            recorder.onstop = () => {
                const finalBlob = new Blob(chunks, { type: mimeType });
                cleanup();
                resolve({ blob: finalBlob, extension });
            };

            recorder.onerror = (e) => {
                console.error("Recorder error:", e);
                // Non rejectiamo qui, aspettiamo onstop o timeout
            };

            // 8. Loop Disegno
            const draw = () => {
                // Controllo se il componente è stato smontato o cleanup chiamato
                if (cleanupDone || !video || video.paused || video.ended) return;

                // Disegna video ridimensionato
                try {
                    ctx.drawImage(video, 0, 0, width, height);

                    // Disegna Watermark
                    // Logica: 25% larghezza o min 120px
                    const wmScale = 0.25;
                    let w = width * wmScale;
                    if (w < 120) w = 120;
                    if (w > width / 2) w = width / 2; // Mai troppo grande

                    const ratio = wmImg.width / wmImg.height;
                    let h = w / ratio;

                    // Posizione: Angolo in basso a destra con padding
                    const padding = width * 0.03; // 3% padding
                    const x = width - w - padding;
                    const y = height - h - padding;

                    ctx.globalAlpha = 0.85;
                    ctx.drawImage(wmImg, x, y, w, h);
                    ctx.globalAlpha = 1.0;

                    requestAnimationFrame(draw);
                } catch (e) {
                    console.error("Errore draw loop", e);
                }
            };

            // Avvio
            recorder.start();

            // Tentativo robusto di playback
            try {
                await video.play();
                draw();
            } catch (playError) {
                console.warn("Autoplay bloccato con audio. Riprovo in mute...", playError);
                // Fallback: Mute e riprova (meglio video senza audio che errore)
                video.muted = true;
                try {
                    await video.play();
                    draw();
                } catch (retryError) {
                    cleanup();
                    reject(new Error("Impossibile avviare riproduzione video per processing."));
                    return;
                }
            }

            video.onended = () => {
                if (recorder.state !== 'inactive') {
                    recorder.stop();
                }
            };

        } catch (error: any) {
            cleanup();
            console.error("Errore critico addWatermarkToVideo:", error);
            reject(new Error(error.message || "Errore sconosciuto processing video"));
        }
    });
};

/**
 * Servizio per il processing video lato client.
 * Aggiunge una filigrana (watermark) sovraimpressa permanentemente al video.
 */

export const addWatermarkToVideo = async (videoFile: File, watermarkUrl: string): Promise<{ blob: Blob, extension: string }> => {
    return new Promise(async (resolve, reject) => {
        let video: HTMLVideoElement | null = null;
        let audioCtx: AudioContext | null = null;
        let objectUrlToRevoke: string | null = null;
        let cleanupDone = false;
        let timeoutId: any = null;

        // Funzione di cleanup sicura da chiamare una sola volta
        const cleanup = () => {
            if (cleanupDone) return;
            cleanupDone = true;
            console.log("Esecuzione cleanup video utils...");

            if (timeoutId) clearTimeout(timeoutId);

            if (audioCtx) {
                try { audioCtx.close(); } catch(e) {}
            }
            if (video) {
                video.pause();
                video.src = "";
                video.load();
                if (video.parentNode) {
                    document.body.removeChild(video);
                }
            }
            if (objectUrlToRevoke) {
                URL.revokeObjectURL(objectUrlToRevoke);
            }
        };

        // Timeout di sicurezza (30 secondi max per il processing)
        timeoutId = setTimeout(() => {
            cleanup();
            reject(new Error("Timeout: Il processo ha impiegato troppo tempo."));
        }, 30000);

        try {
            // Helper per caricare immagine in modo sicuro
            const loadImg = async (url: string): Promise<HTMLImageElement> => {
                // TENTATIVO 1: Fetch come Blob (più robusto per CORS su HTTP)
                if (url.startsWith('http')) {
                    try {
                        const response = await fetch(url, { mode: 'cors' });
                        if (response.ok) {
                            const blob = await response.blob();
                            const blobUrl = URL.createObjectURL(blob);
                            objectUrlToRevoke = blobUrl; 
                            return await loadImgAsElement(blobUrl, false); 
                        }
                    } catch (e) {
                        console.warn("Fetch watermark fallito, tento caricamento standard Image...", e);
                    }
                }

                // TENTATIVO 2 (Data URI o Fallback HTTP)
                const needCors = !url.startsWith('data:') && !url.startsWith('blob:');
                return await loadImgAsElement(url, needCors);
            };

            const loadImgAsElement = (src: string, useCors: boolean): Promise<HTMLImageElement> => {
                return new Promise((res, rej) => {
                    const img = new Image();
                    if (useCors) {
                        img.crossOrigin = 'anonymous';
                    }
                    img.onload = () => res(img);
                    img.onerror = (e) => rej(new Error(`Impossibile caricare file immagine.`));
                    img.src = src;
                });
            };

            console.log("Inizio processing video...");

            // 1. Carica l'immagine Watermark
            const wmImg = await loadImg(watermarkUrl);

            // 2. Prepara l'elemento Video
            // USARE POSIZIONAMENTO OFF-SCREEN (più sicuro di display:none o opacity)
            video = document.createElement('video');
            video.playsInline = true;
            video.preload = 'auto';
            video.muted = false; // Proviamo con audio attivo
            video.src = URL.createObjectURL(videoFile);

            // Stile per nasconderlo ma mantenerlo nel render tree
            video.style.position = 'fixed';
            video.style.top = '-10000px';
            video.style.left = '-10000px';
            video.style.width = '640px'; // Dimensione fissa per evitare layout thrashing iniziale
            video.style.height = '360px';
            video.style.zIndex = '-9999';
            video.style.visibility = 'visible'; // Importante per Safari

            document.body.appendChild(video);

            // Attendi caricamento metadati E canplay
            await new Promise((res, rej) => {
                let loaded = false;

                const onReady = () => {
                    if (!loaded) {
                        loaded = true;
                        res(true);
                    }
                };

                video!.onloadedmetadata = onReady;
                video!.oncanplay = onReady;
                video!.onerror = (e) => {
                    const msg = typeof e === 'string' ? e : (e.target as HTMLMediaElement)?.error?.message;
                    rej(new Error(`Errore caricamento video source: ${msg || 'Errore sconosciuto'}`));
                };

                // Timeout caricamento source (5s)
                setTimeout(() => {
                    if (!loaded) rej(new Error("Timeout caricamento metadati video."));
                }, 5000);
            });

            // 3. Calcolo Risoluzione Ottimizzata (Max 720p/1280px per stabilità)
            const MAX_DIMENSION = 1280;
            let width = video.videoWidth;
            let height = video.videoHeight;

            if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
                const ratio = width / height;
                if (width > height) {
                    width = MAX_DIMENSION;
                    height = width / ratio;
                } else {
                    height = MAX_DIMENSION;
                    width = height * ratio;
                }
                console.log(`Video ridimensionato a ${Math.round(width)}x${Math.round(height)} per performance.`);
            }

            // 4. Prepara Canvas
            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d', { alpha: false }); 

            if (!ctx) throw new Error("Canvas 2D context null.");

            // 5. Setup Audio Context (Safe approach)
            // Se fallisce l'audio context, procediamo senza audio invece di bloccare tutto
            let source: MediaElementAudioSourceNode | null = null;
            let dest: MediaStreamAudioDestinationNode | null = null;

            try {
                const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
                if (AudioContext) {
                    audioCtx = new AudioContext();
                    if (audioCtx.state === 'suspended') {
                        await audioCtx.resume();
                    }
                    source = audioCtx.createMediaElementSource(video);
                    dest = audioCtx.createMediaStreamDestination();
                    source.connect(dest);
                }
            } catch (audioErr) {
                console.warn("AudioContext fallito, il video sarà muto:", audioErr);
            }

            // 6. Determina Formato Output
            let mimeType = '';
            let extension = '';

            const types = [
                'video/mp4',
                'video/webm;codecs=vp9',
                'video/webm;codecs=vp8',
                'video/webm'
            ];

            for (const t of types) {
                if (MediaRecorder.isTypeSupported(t)) {
                    mimeType = t;
                    extension = t.includes('mp4') ? 'mp4' : 'webm';
                    break;
                }
            }
            if (!mimeType) throw new Error("MediaRecorder non supportato dal browser.");

            // 7. Stream Combinato
            const streamFn = (canvas as any).captureStream || (canvas as any).webkitCaptureStream;
            if (!streamFn) throw new Error("Canvas captureStream non supportato.");

            const canvasStream = streamFn.call(canvas, 30); // 30 FPS

            const tracks = [...canvasStream.getVideoTracks()];

            // Aggiungi audio se disponibile
            if (dest) {
                const audioTracks = dest.stream.getAudioTracks();
                if (audioTracks.length > 0) {
                    tracks.push(...audioTracks);
                }
            }

            const combinedStream = new MediaStream(tracks);

            const recorder = new MediaRecorder(combinedStream, { 
                mimeType,
                videoBitsPerSecond: 2500000 // 2.5 Mbps target
            });

            const chunks: Blob[] = [];
            recorder.ondataavailable = (e) => {
                if (e.data.size > 0) chunks.push(e.data);
            };

            recorder.onstop = () => {
                const finalBlob = new Blob(chunks, { type: mimeType });
                cleanup();
                resolve({ blob: finalBlob, extension });
            };

            recorder.onerror = (e) => {
                console.error("Recorder error:", e);
                // Non rejectiamo qui, aspettiamo onstop o timeout
            };

            // 8. Loop Disegno
            const draw = () => {
                // Controllo se il componente è stato smontato o cleanup chiamato
                if (cleanupDone || !video || video.paused || video.ended) return;

                // Disegna video ridimensionato
                try {
                    ctx.drawImage(video, 0, 0, width, height);

                    // Disegna Watermark
                    // Logica: 25% larghezza o min 120px
                    const wmScale = 0.25;
                    let w = width * wmScale;
                    if (w < 120) w = 120;
                    if (w > width / 2) w = width / 2; // Mai troppo grande

                    const ratio = wmImg.width / wmImg.height;
                    let h = w / ratio;

                    // Posizione: Angolo in basso a destra con padding
                    const padding = width * 0.03; // 3% padding
                    const x = width - w - padding;
                    const y = height - h - padding;

                    ctx.globalAlpha = 0.85;
                    ctx.drawImage(wmImg, x, y, w, h);
                    ctx.globalAlpha = 1.0;

                    requestAnimationFrame(draw);
                } catch (e) {
                    console.error("Errore draw loop", e);
                }
            };

            // Avvio
            recorder.start();

            // Tentativo robusto di playback
            try {
                await video.play();
                draw();
            } catch (playError) {
                console.warn("Autoplay bloccato con audio. Riprovo in mute...", playError);
                // Fallback: Mute e riprova (meglio video senza audio che errore)
                video.muted = true;
                try {
                    await video.play();
                    draw();
                } catch (retryError) {
                    cleanup();
                    reject(new Error("Impossibile avviare riproduzione video per processing."));
                    return;
                }
            }

            video.onended = () => {
                if (recorder.state !== 'inactive') {
                    recorder.stop();
                }
            };

        } catch (error: any) {
            cleanup();
            console.error("Errore critico addWatermarkToVideo:", error);
            reject(new Error(error.message || "Errore sconosciuto processing video"));
        }
    });
};

/**
 * Servizio per il processing video lato client.
 * Aggiunge una filigrana (watermark) sovraimpressa permanentemente al video.
 * Versione 3.0: Refactoring completo per stabilità.
 */

export const addWatermarkToVideo = async (videoFile: File, watermarkUrl: string): Promise<{ blob: Blob, extension: string }> => {
    return new Promise(async (resolve, reject) => {
        let video: HTMLVideoElement | null = null;
        let objectUrlToRevoke: string | null = null;
        let recorder: MediaRecorder | null = null;
        let cleanupDone = false;

        // Timeout di sicurezza
        const timeoutId = setTimeout(() => {
            cleanup();
            reject(new Error("Timeout: Processing video troppo lento (max 60s)."));
        }, 60000);

        const cleanup = () => {
            if (cleanupDone) return;
            cleanupDone = true;
            clearTimeout(timeoutId);

            if (video) {
                video.pause();
                video.src = "";
                video.load();
                video.remove();
            }
            if (objectUrlToRevoke) URL.revokeObjectURL(objectUrlToRevoke);
        };

        try {
            console.log("VideoUtils: Inizio processing V3...");

            // 1. CARICAMENTO IMMAGINE FILIGRANA (Gestione CORS robusta)
            const img = new Image();
            img.crossOrigin = 'anonymous';

            await new Promise((res, rej) => {
                img.onload = res;
                img.onerror = () => {
                    // Fallback: se fallisce il caricamento diretto, prova fetch blob
                    console.log("Caricamento diretto fallito, tento fetch blob...");
                    fetch(watermarkUrl)
                        .then(r => r.blob())
                        .then(b => {
                            const bUrl = URL.createObjectURL(b);
                            objectUrlToRevoke = bUrl; // Mark for cleanup
                            img.src = bUrl;
                            // Reset handlers to avoid infinite loop
                            img.onload = res;
                            img.onerror = () => rej(new Error("Impossibile caricare immagine filigrana."));
                        })
                        .catch(e => rej(new Error("Fetch filigrana fallita: " + e.message)));
                };
                img.src = watermarkUrl;
            });

            // 2. SETUP VIDEO ELEMENT
            video = document.createElement('video');
            video.crossOrigin = 'anonymous';
            video.playsInline = true;
            video.muted = true; // Muto per evitare blocchi autoplay, l'audio lo prendiamo dallo stream
            video.preload = 'auto';
            video.src = URL.createObjectURL(videoFile);

            // Hack CSS per rendering background
            video.style.position = 'fixed';
            video.style.top = '0';
            video.style.left = '0';
            video.style.opacity = '0.01'; // Non 0, per sicurezza rendering
            video.style.pointerEvents = 'none';
            video.style.zIndex = '-9999';
            document.body.appendChild(video);

            await new Promise((res, rej) => {
                video!.onloadedmetadata = res;
                video!.onerror = (e: any) => rej(new Error("Errore caricamento video: " + (e.target?.error?.message || "unknown")));
            });

            // 3. SETUP CANVAS
            // Dimensioni devono essere pari per alcuni encoder
            let width = video.videoWidth;
            let height = video.videoHeight;
            // Downscale se troppo grande (max 1080p)
            const MAX_SIZE = 1280; // 720p safe bet for mobile web
            if (width > MAX_SIZE || height > MAX_SIZE) {
                const ratio = width / height;
                if (width > height) {
                    width = MAX_SIZE;
                    height = Math.round(width / ratio);
                } else {
                    height = MAX_SIZE;
                    width = Math.round(height * ratio);
                }
            }
            // Ensure even numbers
            width = width - (width % 2);
            height = height - (height % 2);

            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d', { alpha: false, desynchronized: true });
            if (!ctx) throw new Error("Canvas context failed");

            // 4. AUDIO & VIDEO STREAMS
            // Cattura stream audio dal video element (Chrome/FF/Edge supportano captureStream)
            let audioTrack: MediaStreamTrack | null = null;

            // Rilevamento metodo captureStream
            const captureStreamFn = (video as any).captureStream || (video as any).mozCaptureStream;
            if (captureStreamFn) {
                try {
                    const videoElemStream = captureStreamFn.call(video);
                    const tracks = videoElemStream.getAudioTracks();
                    if (tracks.length > 0) audioTrack = tracks[0];
                } catch (e) {
                    console.warn("Impossibile catturare audio dal video element", e);
                }
            }

            // Canvas Stream
            const canvasStream = canvas.captureStream(30); // 30 FPS target
            const outputTracks = [...canvasStream.getVideoTracks()];
            if (audioTrack) {
                outputTracks.push(audioTrack);
            }

            const combinedStream = new MediaStream(outputTracks);

            // 5. MEDIA RECORDER
            const mimeTypes = [
                'video/webm;codecs=vp8',
                'video/webm',
                'video/mp4' // Safari 14.1+
            ];
            let selectedMime = mimeTypes.find(m => MediaRecorder.isTypeSupported(m)) || '';

            if (!selectedMime) {
                // Fallback estremo
                console.warn("Nessun MIME type specifico supportato, provo default");
                selectedMime = 'video/webm';
            }

            recorder = new MediaRecorder(combinedStream, {
                mimeType: selectedMime,
                videoBitsPerSecond: 2500000 // 2.5 Mbps
            });

            const chunks: Blob[] = [];
            recorder.ondataavailable = (e) => {
                if (e.data && e.data.size > 0) chunks.push(e.data);
            };

            recorder.onstop = () => {
                const blob = new Blob(chunks, { type: selectedMime });
                const ext = selectedMime.includes('mp4') ? 'mp4' : 'webm';
                console.log(`Processing completato: ${blob.size} bytes`);
                cleanup();
                resolve({ blob, extension: ext });
            };

            recorder.onerror = (e: any) => {
                cleanup();
                reject(new Error("Recorder error: " + (e.error?.message || "unknown")));
            };

            // 6. RENDER LOOP
            // Usiamo requestVideoFrameCallback se disponibile (più efficiente)
            // altrimenti fallback a requestAnimationFrame
            const hasRVFC = 'requestVideoFrameCallback' in video;

            const renderFrame = () => {
                if (!video || video.paused || video.ended) return;

                // Disegna frame
                ctx.drawImage(video, 0, 0, width, height);

                // Disegna Watermark
                const wmW = Math.max(width * 0.2, 120); // 20% width o min 120px
                const wmRatio = img.width / img.height;
                const wmH = wmW / wmRatio;
                const padding = width * 0.04;

                ctx.globalAlpha = 0.8;
                ctx.drawImage(img, width - wmW - padding, height - wmH - padding, wmW, wmH);
                ctx.globalAlpha = 1.0;

                if (hasRVFC) {
                    (video as any).requestVideoFrameCallback(renderFrame);
                } else {
                    requestAnimationFrame(renderFrame);
                }
            };

            // START
            recorder.start();

            // Audio workaround: per catturare l'audio con captureStream, il video NON deve essere mutato
            // Ma se non è mutato, autoplay blocca.
            // Soluzione: Mute -> Play -> Unmute (se allowed) -> Record
            // Tuttavia, se l'utente non ha interagito, unmute fallisce.
            // PROVIAMO APPROCCIO IBRIDO:
            // Lasciamo muted=true. captureStream spesso cattura l'audio MUTO.
            // Se vogliamo l'audio, dobbiamo usare WebAudio o sperare che il browser sia smart.
            // FIX: Impostiamo muted=false ma volume=0 ? No, volume impatta lo stream.
            // Tentiamo il play MUTED. Se captureStream prende l'audio sorgente (alcuni browser lo fanno), bene.
            // Altrimenti, per ora accettiamo video senza audio come fallback al crash.

            // TRICK: Se siamo in un contesto gestito dall'utente (click upload), l'audio dovrebbe essere permesso.
            video.muted = false; 

            try {
                await video.play();
            } catch (e) {
                console.warn("Autoplay audio bloccato. Procedo mutato.");
                video.muted = true;
                await video.play();
            }

            if (hasRVFC) {
                (video as any).requestVideoFrameCallback(renderFrame);
            } else {
                renderFrame();
            }

            video.onended = () => {
                recorder?.stop();
            };

        } catch (e: any) {
            cleanup();
            console.error("VideoUtils Error:", e);
            reject(new Error(e.message || "Errore sconosciuto"));
        }
    });
};

