                    const wmScale = 0.20; 
                    let wmW = width * wmScale;
                    if (wmW < 100) wmW = 100;
                    if (wmW > 400) wmW = 400;

                    const wmRatio = img.width / img.height;
                    let wmH = wmW / wmRatio;

                    // Posizione: in basso a destra con padding
                    const padding = Math.max(20, width * 0.03);
                    const x = width - wmW - padding;
                    const y = height - wmH - padding;

                    // Disegna Watermark
                    ctx.globalAlpha = 0.85; // Leggera trasparenza
                    ctx.drawImage(img, x, y, wmW, wmH);
                    ctx.globalAlpha = 1.0;

                    // Loop
                    if (hasRVFC) {
                        (video as any).requestVideoFrameCallback(renderFrame);
                    } else {
                        requestAnimationFrame(renderFrame);
                    }
                } catch (err) {
                    console.error("Frame render error", err);
                    // Non fermiamo il recorder, magari il prossimo frame va bene
                }
            };

            // START PROCESS
            recorder.start();

            // Gestione Playback
            // Per catturare l'audio su Chrome con captureStream, il video deve riprodurre audio.
            // Tuttavia, se l'utente non ha interagito, video.play() non mutato fallisce.
            // Strategia: Play normale. Se fallisce, play muted (perdiamo audio ma salviamo video).

            video.muted = false; 
            try {
                await video.play();
            } catch (e) {
                console.warn("Autoplay audio blocked. Fallback to muted processing (Audio lost).");
                video.muted = true;
                await video.play();
            }

            if (hasRVFC) {
                (video as any).requestVideoFrameCallback(renderFrame);
            } else {
                renderFrame();
            }

            video.onended = () => {
                recorder?.stop();
            };

        } catch (e: any) {
            cleanup();
            console.error("VideoUtils Critical Error:", e);
            reject(new Error(e.message || "Errore sconosciuto durante il processing"));
        }
    });
};

/**
 * Servizio per il processing video lato client.
 * Aggiunge una filigrana (watermark) sovraimpressa permanentemente al video.
 * Versione 5.0: Stable Fetch & Base64 Handling.
 */

export const addWatermarkToVideo = async (videoFile: File, watermarkUrl: string): Promise<{ blob: Blob, extension: string }> => {
    return new Promise(async (resolve, reject) => {
        let video: HTMLVideoElement | null = null;
        let objectUrlToRevoke: string | null = null; // Per i blob creati manualmente (img)
        let videoUrlToRevoke: string | null = null;  // Per il video sorgente
        let recorder: MediaRecorder | null = null;
        let cleanupDone = false;

        // Timeout di sicurezza
        const timeoutId = setTimeout(() => {
            cleanup();
            reject(new Error("Timeout: Processing video troppo lento (max 60s)."));
        }, 60000);

        const cleanup = () => {
            if (cleanupDone) return;
            cleanupDone = true;
            clearTimeout(timeoutId);

            if (video) {
                video.pause();
                video.src = "";
                video.load();
                video.remove();
            }
            if (objectUrlToRevoke) URL.revokeObjectURL(objectUrlToRevoke);
            if (videoUrlToRevoke) URL.revokeObjectURL(videoUrlToRevoke);
        };

        try {
            console.log("VideoUtils: Inizio processing V5...");

            // 1. CARICAMENTO IMMAGINE FILIGRANA ROBUSTO
            const loadWatermark = async (url: string): Promise<HTMLImageElement> => {
                const cleanUrl = url.trim();
                const isDataUri = cleanUrl.startsWith('data:');

                if (isDataUri) {
                    // --- PERCORSO A: BASE64 (DATA URI) ---
                    // Carichiamo direttamente. NON usare fetch su data URI.
                    // NON usare crossOrigin su data URI (causa errori su Safari).
                    return new Promise((res, rej) => {
                        const img = new Image();
                        img.onload = () => res(img);
                        img.onerror = () => rej(new Error("Data URI filigrana corrotto o non valido."));
                        img.src = cleanUrl;
                    });
                } else {
                    // --- PERCORSO B: HTTP URL ---
                    // Dobbiamo usare fetch per creare un Blob locale.
                    // Se usiamo img.src = http_url, il canvas diventa "tainted" e captureStream fallisce.
                    try {
                        const response = await fetch(cleanUrl, { mode: 'cors' });
                        if (!response.ok) throw new Error(`Fetch error: ${response.status}`);
                        const blob = await response.blob();
                        const blobUrl = URL.createObjectURL(blob);
                        objectUrlToRevoke = blobUrl; // Segniamo per il cleanup

                        return new Promise((res, rej) => {
                            const img = new Image();
                            img.onload = () => res(img);
                            img.onerror = () => rej(new Error("Impossibile decodificare immagine dal Blob."));
                            img.src = blobUrl;
                        });
                    } catch (e: any) {
                        console.error("Errore fetch watermark:", e);
                        throw new Error(`Impossibile scaricare la filigrana remota: ${e.message}. Assicurati che l'URL permetta CORS o usa Base64.`);
                    }
                }
            };

            const img = await loadWatermark(watermarkUrl);

            // 2. SETUP VIDEO ELEMENT
            videoUrlToRevoke = URL.createObjectURL(videoFile);
            video = document.createElement('video');
            video.crossOrigin = 'anonymous';
            video.playsInline = true;
            video.muted = true; // Necessario per autoplay
            video.preload = 'auto';
            video.src = videoUrlToRevoke;

            // Stile invisibile ma renderizzato
            video.style.position = 'fixed';
            video.style.top = '0';
            video.style.left = '0';
            video.style.opacity = '0.01'; 
            video.style.pointerEvents = 'none';
            video.style.zIndex = '-9999';
            document.body.appendChild(video);

            await new Promise((res, rej) => {
                video!.onloadedmetadata = res;
                video!.onerror = (e: any) => rej(new Error("Errore caricamento video: " + (e.target?.error?.message || "unknown")));
            });

            // 3. SETUP CANVAS
            let width = video.videoWidth;
            let height = video.videoHeight;

            // Downscale (Max 720p per performance mobile)
            const MAX_SIZE = 1280; 
            if (width > MAX_SIZE || height > MAX_SIZE) {
                const ratio = width / height;
                if (width > height) {
                    width = MAX_SIZE;
                    height = Math.round(width / ratio);
                } else {
                    height = MAX_SIZE;
                    width = Math.round(height * ratio);
                }
            }
            // Dimensioni pari (Even numbers) obbligatorie per encoder video
            width = width - (width % 2);
            height = height - (height % 2);

            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d', { alpha: false, desynchronized: true });
            if (!ctx) throw new Error("Canvas context failed");

            // 4. AUDIO STREAM
            let audioTrack: MediaStreamTrack | null = null;
            // Tentativo prioritario: captureStream dal video element (funziona su Chrome/Edge se video ha audio)
            const captureStreamFn = (video as any).captureStream || (video as any).mozCaptureStream;

            if (captureStreamFn) {
                try {
                    const videoElemStream = captureStreamFn.call(video);
                    const tracks = videoElemStream.getAudioTracks();
                    if (tracks.length > 0) audioTrack = tracks[0];
                } catch (e) {
                    console.warn("Audio capture warning:", e);
                }
            }

            // 5. COMBINED STREAM
            const canvasStream = canvas.captureStream(30); // 30 FPS constant
            const outputTracks = [...canvasStream.getVideoTracks()];
            if (audioTrack) {
                outputTracks.push(audioTrack);
            }

            const combinedStream = new MediaStream(outputTracks);

            // 6. MEDIA RECORDER SETUP
            const mimeTypes = [
                'video/mp4', // Safari 14.1+
                'video/webm;codecs=vp8', // Chrome/FF Standard
                'video/webm'
            ];
            let selectedMime = mimeTypes.find(m => MediaRecorder.isTypeSupported(m)) || '';
            if (!selectedMime) selectedMime = 'video/webm'; // Fallback

            recorder = new MediaRecorder(combinedStream, {
                mimeType: selectedMime,
                videoBitsPerSecond: 2500000 // 2.5 Mbps Quality
            });

            const chunks: Blob[] = [];
            recorder.ondataavailable = (e) => {
                if (e.data && e.data.size > 0) chunks.push(e.data);
            };

            recorder.onstop = () => {
                const blob = new Blob(chunks, { type: selectedMime });
                const ext = selectedMime.includes('mp4') ? 'mp4' : 'webm';
                cleanup();
                resolve({ blob, extension: ext });
            };

            recorder.onerror = (e: any) => {
                cleanup();
                reject(new Error("Recorder error: " + (e.error?.message || "unknown")));
            };

            // 7. RENDER LOOP
            const hasRVFC = 'requestVideoFrameCallback' in video;

            const renderFrame = () => {
                if (!video || video.paused || video.ended || cleanupDone) return;

                try {
                    // Draw Video Frame
                    ctx.drawImage(video, 0, 0, width, height);

                    // Draw Watermark
                    // Logica: 20% width, min 100px, max 300px
                    let wmW = width * 0.20;
                    if (wmW < 100) wmW = 100;
                    if (wmW > 300) wmW = 300;

                    const wmRatio = img.width / img.height;
                    let wmH = wmW / wmRatio;

                    const padding = width * 0.03; // 3% padding
                    const x = width - wmW - padding;
                    const y = height - wmH - padding;

                    ctx.globalAlpha = 0.85;
                    ctx.drawImage(img, x, y, wmW, wmH);
                    ctx.globalAlpha = 1.0;

                    if (hasRVFC) {
                        (video as any).requestVideoFrameCallback(renderFrame);
                    } else {
                        requestAnimationFrame(renderFrame);
                    }
                } catch (err) {
                    console.error("Render error (ignored):", err);
                }
            };

            // 8. START PLAYBACK & RECORDING
            recorder.start();

            // Audio workaround: Video must be playing to capture audio via captureStream.
            // But unmuted autoplay is often blocked.
            // Strategy: Try play unmuted. If fails, play muted (audio lost, but video saved).
            video.muted = false; 

            try {
                await video.play();
            } catch (e) {
                console.warn("Autoplay blocked. Fallback to muted processing.", e);
                video.muted = true;
                await video.play();
            }

            // Start loop
            if (hasRVFC) {
                (video as any).requestVideoFrameCallback(renderFrame);
            } else {
                renderFrame();
            }

            video.onended = () => {
                if (recorder && recorder.state !== 'inactive') {
                    recorder.stop();
                }
            };

        } catch (e: any) {
            cleanup();
            console.error("VideoUtils Critical Failure:", e);
            reject(new Error(e.message || "Errore sconosciuto processing video"));
        }
    });
};

