export const uploadWatermark = async (file: Blob): Promise<string> => {
    if (file.size > 500 * 1024) throw new Error("File troppo grande (Max 500KB)");
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = async () => {
            const base64String = reader.result as string;
            const settingsRef = doc(db, 'settings', 'global');
            await updateDoc(settingsRef, { watermarkUrl: base64String });
            await logAction(auth.currentUser?.uid || 'system', 'upload_watermark', 'Caricata nuova filigrana');
            resolve(base64String);
        };
        reader.onerror = reject;
    });
};

