};

export const getCategories = async (): Promise<string[]> => {
    const categoriesRef = collection(db, 'categories');
    const snapshot = await getDocs(categoriesRef);
    if (snapshot.empty) {
        const batch = writeBatch(db);
        DB_CATEGORIES_SEED.forEach(catName => batch.set(doc(categoriesRef), { name: catName }));
        await batch.commit();
        return DB_CATEGORIES_SEED.sort();
    }
    return snapshot.docs.map(d => d.data().name).sort();
};

export const getTalents = async (): Promise<Talent[]> => {
    const q = query(collection(db, 'users'), where('role', '==', UserRole.TALENT), where('isApproved', '==', true));
    const snap = await getDocs(q);
    if (snap.empty) return MOCK_TALENTS.map(t => ({ ...t, isAvailable: true, isApproved: true }));
    return snap.docs.map(d => ({ id: d.id, isAvailable: d.data().isAvailable !== false, ...d.data() } as Talent));
};

