    const status = decision === 'FAN_WINS' ? RequestStatus.CORRECTION_NEEDED : RequestStatus.COMPLETED;
    await updateDoc(doc(db, 'requests', requestId), { status, adminNoteFan, adminNoteTalent, updatedAt: new Date().toISOString() });
