export const uploadAvatar = async (file: Blob, userId: string): Promise<string> => {
    const storageRef = ref(storage, `avatars/${userId}/avatar_${Date.now()}.jpg`);
    await uploadBytes(storageRef, file, { contentType: 'image/jpeg' });
    const url = await getDownloadURL(storageRef);
    await updateDoc(doc(db, 'users', userId), { avatarUrl: url });
    return url;
};

export const checkExpirations = async () => {
    const now = new Date().getTime();
    const snap = await getDocs(query(collection(db, 'requests'), where('status', 'in', [RequestStatus.PENDING, RequestStatus.IN_REVIEW])));
    for (const d of snap.docs) {
        const req = d.data() as VideoRequest;
        if (req.status === RequestStatus.PENDING && req.expiresAt && now > new Date(req.expiresAt).getTime()) {
            await updateDoc(d.ref, { status: RequestStatus.EXPIRED, updatedAt: new Date().toISOString() });
        }
    }
};

