const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [adminSettings, setAdminSettings] = useState<AdminSettings | null>(null);

  useEffect(() => {
    const unsubscribe = firebaseAuth.onAuthStateChanged(auth, async (firebaseUser) => {
      // Carica impostazioni globali
      const settings = await getAdminSettings();
      setAdminSettings(settings);

      if (firebaseUser) {
        const initialUser: User = {
          id: firebaseUser.uid,
          name: firebaseUser.displayName || 'Utente',
          email: firebaseUser.email || '',
          role: UserRole.FAN,
          avatarUrl: firebaseUser.photoURL || undefined
        };

        try {
          const dbUser = await syncUserToDB(initialUser);
          setUser(dbUser);
        } catch (error) {
          console.error("Errore sync user:", error);
          setUser(initialUser);
        }
      } else {
        setUser(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleLogout = async () => {
    await firebaseAuth.signOut(auth);
  };

  if (loading) {
    return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50">
            <Loader2 className="w-10 h-10 animate-spin text-slate-900" />
        </div>
    );
  }

  // GESTIONE MAINTENANCE MODE
  const isMaintenanceActive = adminSettings?.maintenanceMode && user?.role !== UserRole.ADMIN;

  return (
    <Router>
      <div className="min-h-screen bg-gray-50">
        <Navbar user={user} onLogout={handleLogout} />

        {isMaintenanceActive ? (
            <div className="max-w-4xl mx-auto px-4 py-20 text-center">
                <div className="bg-white p-12 rounded-3xl shadow-xl border border-gray-100 flex flex-col items-center">
                    <AlertCircle className="w-20 h-20 text-red-500 mb-6 animate-pulse" />
                    <h1 className="text-4xl font-black text-slate-900 mb-4 uppercase tracking-tight">Manutenzione Straordinaria</h1>
                    <p className="text-xl text-slate-600 mb-8 font-light leading-relaxed">
                        Ciao! Stiamo aggiornando CiaoStar per offrirti un'esperienza ancora più magica.<br/>
                        Il sistema tornerà online a breve. Grazie per la pazienza!
                    </p>
                    <div className="text-xs font-black text-slate-400 uppercase tracking-widest">Team CiaoStar</div>
                </div>
            </div>
        ) : (
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={!user ? <Login onLogin={() => {}} /> : <Navigate to="/" />} />
              <Route 
                path="/talent/:id" 
                element={<TalentProfile currentUser={user} />} 
              />
              <Route 
                path="/dashboard" 
                element={
                  user ? <Dashboard user={user} /> : <Navigate to="/login" replace />
                } 
              />
              <Route 
                path="/messages" 
                element={
                  user ? <UserChat user={user} /> : <Navigate to="/login" replace />
                } 
              />
              <Route 
                path="/settings" 
                element={
                  user && user.role === UserRole.TALENT ? <TalentSettings user={user} /> : <Navigate to="/" replace />
                } 
              />
              <Route 
                path="/admin" 
                element={
                  user && user.role === UserRole.ADMIN ? <AdminDashboard user={user} /> : <Navigate to="/" replace />
                } 
              />
              <Route 
                path="/admin/chat" 
                element={
