export const uploadWatermark = async (file: Blob): Promise<string> => {
    if (file.size > 500 * 1024) throw new Error("File troppo grande (Max 500KB)");
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = async () => {
            const base64String = reader.result as string;
            const settingsRef = doc(db, 'settings', 'global');
            await updateDoc(settingsRef, { watermarkUrl: base64String });
            await logAction(auth.currentUser?.uid || 'system', 'upload_watermark', 'Caricata nuova filigrana');
            resolve(base64String);
        };
        reader.onerror = reject;
    });
};

export const deleteWatermark = async () => {
    const settingsRef = doc(db, 'settings', 'global');
    await updateDoc(settingsRef, { watermarkUrl: deleteField() });
    await logAction(auth.currentUser?.uid || 'system', 'delete_watermark', 'Eliminata filigrana');
};

export const getCategories = async (): Promise<string[]> => {
    const categoriesRef = collection(db, 'categories');
    const snapshot = await getDocs(categoriesRef);
    if (snapshot.empty) {
        const batch = writeBatch(db);
        DB_CATEGORIES_SEED.forEach(catName => batch.set(doc(categoriesRef), { name: catName }));
        await batch.commit();
        return DB_CATEGORIES_SEED.sort();
    }
    return snapshot.docs.map(d => d.data().name).sort();
};

