    const q = query(collection(db, 'users'), where('role', '==', UserRole.TALENT), where('isApproved', '==', true));
    const snap = await getDocs(q);
    if (snap.empty) return MOCK_TALENTS.map(t => ({ ...t, isAvailable: true, isApproved: true }));
    return snap.docs.map(d => ({ id: d.id, isAvailable: d.data().isAvailable !== false, ...d.data() } as Talent));
};

export const getTalentById = async (id: string): Promise<Talent | undefined> => {
    const docRef = doc(db, 'users', id);
    const docSnap = await getDoc(docRef);
    if (docSnap.exists()) return { id: docSnap.id, ...docSnap.data() } as Talent;
    return undefined;
};

export const createRequest = async (request: Omit<VideoRequest, 'id' | 'createdAt' | 'status' | 'updatedAt'>): Promise<string> => {
    const settings = await getAdminSettings();
    const now = new Date();
    let expiresAt = new Date(now.getTime() + settings.deliveryDeadlineDays * 24 * 60 * 60 * 1000);
    if (request.isFastDelivery) expiresAt = new Date(now.getTime() + 24 * 60 * 60 * 1000);

    const requestData = { ...request, status: RequestStatus.PENDING, createdAt: now.toISOString(), updatedAt: now.toISOString(), expiresAt: expiresAt.toISOString() };
    const docRef = await addDoc(collection(db, 'requests'), requestData);

    const fee = (request.pricePaid * settings.platformFeePercent) / 100;
    await addDoc(collection(db, 'payments'), {
        requestId: docRef.id, fanId: request.fanId, talentId: request.talentId,
        amount: request.pricePaid, currency: 'EUR', status: 'captured',
        platformFee: fee, talentEarnings: request.pricePaid - fee, createdAt: now.toISOString()
    });
    await logAction(request.fanId, 'create_request', `Ordine creato per €${request.pricePaid}`, docRef.id);
    return docRef.id;
};

export const getRequestsForUser = async (userId: string, role: UserRole): Promise<VideoRequest[]> => {
    const field = role === UserRole.FAN ? 'fanId' : 'talentId';
    const q = query(collection(db, 'requests'), where(field, '==', userId));
    const snap = await getDocs(q);
    return snap.docs.map(d => ({ id: d.id, ...d.data() } as VideoRequest)).sort((a,b) => b.createdAt.localeCompare(a.createdAt));
};

export const uploadVideo = async (file: Blob, requestId: string): Promise<string> => {
    const mimeType = file.type || 'video/mp4';
    const ext = mimeType.includes('webm') ? 'webm' : 'mp4';
    const storageRef = ref(storage, `videos/${requestId}/response_${Date.now()}.${ext}`);
    const snapshot = await uploadBytes(storageRef, file, { contentType: mimeType });
    const url = await getDownloadURL(storageRef);

    const videoDoc = await addDoc(collection(db, 'videos'), { requestId, talentId: auth.currentUser!.uid, url, format: mimeType, sizeBytes: snapshot.metadata.size, createdAt: new Date().toISOString(), views: 0 });
    await updateDoc(doc(db, 'requests', requestId), { status: RequestStatus.IN_REVIEW, videoUrl: url, videoId: videoDoc.id, updatedAt: new Date().toISOString() });
    return url;
};

export const cancelRequestByFan = async (requestId: string): Promise<boolean> => {
    const settings = await getAdminSettings();
    const snap = await getDoc(doc(db, 'requests', requestId));
    if (!snap.exists()) return false;
    const data = snap.data() as VideoRequest;
    if ((new Date().getTime() - new Date(data.createdAt).getTime()) / 60000 > settings.refundWindowMinutes) throw new Error("Tempo scaduto per annullamento.");
    await updateDoc(doc(db, 'requests', requestId), { status: RequestStatus.CANCELED_BY_FAN, updatedAt: new Date().toISOString() });
    return true;
};

export const rejectRequest = async (requestId: string) => {
    await updateDoc(doc(db, 'requests', requestId), { status: RequestStatus.REJECTED, updatedAt: new Date().toISOString() });
};

export const completeOrder = async (requestId: string) => {
