};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import TalentProfile from './pages/TalentProfile';
import Dashboard from './pages/Dashboard';
import Login from './pages/Login';
import AdminDashboard from './pages/AdminDashboard';
import { User, UserRole, AdminSettings } from './types';
import { auth } from './firebaseConfig';
import * as firebaseAuth from 'firebase/auth';
import { syncUserToDB, getAdminSettings, acceptNewTerms } from './services/dataService';
import { Loader2, AlertTriangle, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [adminSettings, setAdminSettings] = useState<AdminSettings | null>(null);

  useEffect(() => {
    const unsubscribe = firebaseAuth.onAuthStateChanged(auth, async (firebaseUser) => {
      const settings = await getAdminSettings();
      setAdminSettings(settings);

      if (firebaseUser) {
        const dbUser = await syncUserToDB({ id: firebaseUser.uid, email: firebaseUser.email || '', name: firebaseUser.displayName || 'Utente' });
        setUser(dbUser);
      } else {
        setUser(null);
      }
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  const handleAcceptTerms = async () => {
    if (!user || !adminSettings) return;
    await acceptNewTerms(user.id, adminSettings.termsVersion);
    setUser({ ...user, lastAcceptedTermsVersion: adminSettings.termsVersion });
  };

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin" /></div>;

  // BLOCKING MODAL LOGIC (VIP ONLY)
  const needsTermsUpdate = user?.role === UserRole.TALENT && adminSettings && user.lastAcceptedTermsVersion < adminSettings.termsVersion;

  return (
    <Router>
      <div className="min-h-screen bg-gray-50 flex flex-col">
        <Navbar user={user} onLogout={() => firebaseAuth.signOut(auth)} />

        {needsTermsUpdate && (
            <div className="fixed inset-0 z-[9999] bg-slate-900/90 backdrop-blur-md flex items-center justify-center p-4">
                <div className="bg-white rounded-3xl p-8 max-w-md w-full shadow-2xl text-center">
                    <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-6">
                        <ShieldCheck className="w-8 h-8" />
                    </div>
                    <h2 className="text-2xl font-black text-slate-900 mb-4 uppercase">Regolamento Aggiornato</h2>
                    <p className="text-slate-600 mb-8">
                        Abbiamo aggiornato i termini di servizio di CiaoStar per riflettere le nuove policy di consegna e gestione fiscale.
                    </p>
                    <button 
                        onClick={handleAcceptTerms}
                        className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-black transition-all"
                    >
                        ACCETTO I NUOVI TERMINI
                    </button>
                </div>
            </div>
        )}

        <main className="flex-1">
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={!user ? <Login onLogin={() => {}} /> : <Navigate to="/" />} />
              <Route path="/talent/:id" element={<TalentProfile currentUser={user} />} />
              <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
              <Route path="/admin" element={user?.role === UserRole.ADMIN ? <AdminDashboard user={user} /> : <Navigate to="/" />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

