export const syncUserToDB = async (user: User) => {
  const userRef = doc(db, 'users', user.id);
  const userSnap = await getDoc(userRef);

  let role = user.role;
  if (user.email === ADMIN_EMAIL) {
      role = UserRole.ADMIN;
  }

  if (!userSnap.exists()) {
    const newUser = {
      ...user,
      role: role,
      isApproved: role === UserRole.ADMIN ? true : false, // Solo l'admin è auto-approvato
      createdAt: new Date().toISOString()
    };
    await setDoc(userRef, newUser);
    await logAction(user.id, 'user_signup', `Nuovo utente: ${user.email}`);
    return newUser as User;
  } else {
    const data = userSnap.data();
    if (user.email === ADMIN_EMAIL && data.role !== UserRole.ADMIN) {
        await updateDoc(userRef, { role: UserRole.ADMIN, isApproved: true });
        data.role = UserRole.ADMIN;
    }
    return { ...user, ...data } as User;
  }
};

