};

export const resolveDispute = async (requestId: string, decision: 'FAN_WINS' | 'TALENT_WINS', adminNoteFan?: string, adminNoteTalent?: string) => {
    const status = decision === 'FAN_WINS' ? RequestStatus.CORRECTION_NEEDED : RequestStatus.COMPLETED;
    await updateDoc(doc(db, 'requests', requestId), { status, adminNoteFan, adminNoteTalent, updatedAt: new Date().toISOString() });
};

export const deleteVideoFromRequest = async (requestId: string) => {
    await updateDoc(doc(db, 'requests', requestId), { videoUrl: deleteField(), videoId: deleteField(), status: RequestStatus.PENDING, updatedAt: new Date().toISOString() });
};

export const uploadAvatar = async (file: Blob, userId: string): Promise<string> => {
    const storageRef = ref(storage, `avatars/${userId}/avatar_${Date.now()}.jpg`);
    await uploadBytes(storageRef, file, { contentType: 'image/jpeg' });
    const url = await getDownloadURL(storageRef);
    await updateDoc(doc(db, 'users', userId), { avatarUrl: url });
    return url;
};

export const checkExpirations = async () => {
    const now = new Date().getTime();
    const snap = await getDocs(query(collection(db, 'requests'), where('status', 'in', [RequestStatus.PENDING, RequestStatus.IN_REVIEW])));
    for (const d of snap.docs) {
        const req = d.data() as VideoRequest;
        const expiresAt = req.expiresAt || req.expirationTimestamp;
        if (req.status === RequestStatus.PENDING && expiresAt && now > new Date(expiresAt).getTime()) {
            await updateDoc(d.ref, { status: RequestStatus.EXPIRED, updatedAt: new Date().toISOString() });
        }
    }
};

