export const sendMessage = async (cid: string, sid: string, txt: string, adm: boolean) => {
    const convRef = doc(db, 'conversations', cid);
    await addDoc(collection(convRef, 'messages'), { senderId: sid, text: txt, timestamp: serverTimestamp(), isAdmin: adm });
    const snap = await getDoc(convRef);
    if (!snap.exists()) {
        const u = (await getDoc(doc(db, 'users', cid))).data() as User;
        await setDoc(convRef, { userId: cid, userName: u?.name || 'Utente', userRole: u?.role || UserRole.FAN, lastMessage: txt, lastMessageAt: serverTimestamp(), unreadCountAdmin: adm ? 0 : 1, unreadCountUser: adm ? 1 : 0 });
    } else {
        await updateDoc(convRef, { lastMessage: txt, lastMessageAt: serverTimestamp(), unreadCountAdmin: adm ? 0 : increment(1), unreadCountUser: adm ? increment(1) : 0 });
    }
};
export const subscribeToMessages = (cid: string, cb: (m: ChatMessage[]) => void) => onSnapshot(query(collection(db, 'conversations', cid, 'messages'), orderBy('timestamp', 'asc')), s => cb(s.docs.map(d => ({id: d.id, ...d.data()} as ChatMessage))));
export const subscribeToConversations = (cb: (c: Conversation[]) => void) => onSnapshot(query(collection(db, 'conversations'), orderBy('lastMessageAt', 'desc')), s => cb(s.docs.map(d => ({id: d.id, ...d.data()} as Conversation))));
export const subscribeToMyConversation = (uid: string, cb: (c: Conversation | null) => void) => onSnapshot(doc(db, 'conversations', uid), d => cb(d.exists() ? {id: d.id, ...d.data()} as Conversation : null));
export const markConversationAsRead = async (cid: string, r: UserRole) => updateDoc(doc(db, 'conversations', cid), r === UserRole.ADMIN ? { unreadCountAdmin: 0 } : { unreadCountUser: 0 });
export const updateChatMessage = async (cid: string, mid: string, txt: string) => updateDoc(doc(db, 'conversations', cid, 'messages', mid), { text: txt, isEdited: true });
export const deleteChatMessage = async (cid: string, mid: string) => deleteDoc(doc(db, 'conversations', cid, 'messages', mid));

