  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);

  // General Workflow State
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [processingStatus, setProcessingStatus] = useState<string>('');

  // Dispute Modal State
  const [disputeModalOpen, setDisputeModalOpen] = useState(false);
  const [disputeReason, setDisputeReason] = useState('');
  const [requestToDispute, setRequestToDispute] = useState<VideoRequest | null>(null);

  // Wallet Mock Data
  const [walletData] = useState({
    balance: 185.00,
    pending: 450.00,
    totalEarned: 1250.00,
    nextPayout: '15 Ottobre'
  });

  const refreshData = async () => {
    setLoading(true);
    try {
        // Run checks
        await checkExpirations();

        const [data, settings] = await Promise.all([
            getRequestsForUser(user.id, user.role),
            getAdminSettings()
        ]);
        setRequests(data);
        setAdminSettings(settings);
    } catch (e) {
        console.error("Errore fetch richieste", e);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => {
    refreshData();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  // Cleanup stream on unmount or modal close
  useEffect(() => {
    return () => {
      stopCamera();
    };
  }, []);

  // --- LOGICA TEMPISTICA UNIFICATA ---

  const getRefundState = (req: VideoRequest) => {
      const windowMinutes = adminSettings?.refundWindowMinutes || 30;
      const created = new Date(req.createdAt).getTime();
      const now = new Date().getTime();
      const diffMins = (now - created) / 1000 / 60;
      const isActive = diffMins < windowMinutes;
      const minsLeft = Math.max(0, Math.ceil(windowMinutes - diffMins));
      return { isActive, minsLeft };
  };

  const getDisputeTimeLeft = (req: VideoRequest) => {
      const windowHours = adminSettings?.disputeWindowHours || 48;
      const updated = new Date(req.updatedAt || req.createdAt).getTime();
      const now = new Date().getTime();
      const diffHours = (now - updated) / (1000 * 60 * 60);
      return Math.max(0, Math.ceil(windowHours - diffHours));
  };

  const getDeadlineCountdown = (req: VideoRequest) => {
    const expires = new Date(req.expiresAt || req.expirationTimestamp).getTime();
    if (!expires) return null;
    const now = new Date().getTime();
    const diffMs = expires - now;
    if (diffMs <= 0) return "SCADUTO";
    const days = Math.floor(diffMs / (1000 * 60 * 60 * 24));
    const hours = Math.floor((diffMs % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    const minutes = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
    if (days > 0) return `${days}g ${hours}h`;
    return `${hours}h ${minutes}m`;
  };

  const getUrgencyColor = (req: VideoRequest) => {
    const expires = new Date(req.expiresAt || req.expirationTimestamp).getTime();
    if (!expires) return "bg-gray-100 text-gray-800";
    const now = new Date().getTime();
    const diffHours = (expires - now) / (1000 * 60 * 60);
    if (diffHours < 0) return "bg-gray-200 text-gray-600";
    if (diffHours < 24) return "bg-red-100 text-red-800 border border-red-200 animate-pulse";
    if (diffHours < 72) return "bg-amber-100 text-amber-800 border border-amber-200";
    return "bg-emerald-100 text-emerald-800 border border-emerald-200";
  };

  // --- ACTIONS ---

  const handleCancelOrder = async (requestId: string) => {
      if(!confirm("Sei sicuro di voler annullare l'ordine? Questa azione è irreversibile.")) return;
      try {
          await cancelRequestByFan(requestId);
          alert("Ordine annullato e rimborsato correttamente.");
          refreshData();
      } catch (e: any) {
          alert(e.message || "Errore durante l'annullamento.");
      }
  };

  const handleCompleteOrder = async (req: VideoRequest) => {
      try {
          await completeOrder(req.id);
          confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
          refreshData();
      } catch (e) {
          console.error(e);
          alert("Errore completamento ordine.");
      }
  };

  const handleOpenDisputeModal = (req: VideoRequest) => {
      setRequestToDispute(req);
      setDisputeReason('');
      setDisputeModalOpen(true);
  };

  const submitDispute = async () => {
      if (!requestToDispute || !disputeReason.trim()) return;
      try {
          await openDispute(requestToDispute.id, disputeReason);
          setDisputeModalOpen(false);
          refreshData();
          alert("Contestazione aperta. L'admin esaminerà la richiesta.");
      } catch (e) {
          console.error(e);
          alert("Errore apertura contestazione.");
      }
  };

  const handleRejectRequest = async (requestId: string) => {
      if(!confirm("Sei sicuro di voler rifiutare questa richiesta? L'importo verrà rimborsato al fan.")) return;
      setLoading(true);
      try {
          await rejectRequest(requestId);
          alert("Richiesta rifiutata con successo.");
          refreshData();
      } catch (e) {
          console.error(e);
          alert("Errore durante il rifiuto.");
      } finally {
          setLoading(false);
      }
  };

  const handleDeleteVideo = async (req: VideoRequest) => {
      if(!confirm("Sei sicuro di voler eliminare questo video? La richiesta tornerà in stato 'In attesa'.")) return;
      setLoading(true);
      try {
          await deleteVideoFromRequest(req.id);
          await refreshData();
          alert("Video eliminato.");
      } catch (e: any) {
          console.error(e);
          alert(e.message || "Errore durante l'eliminazione.");
      } finally {
          setLoading(false);
      }
  };

  // --- DEVELOPER ACTIONS ---
  const handleBecomeTalent = async () => {
    if (!confirm("Vuoi trasformare questo account in un profilo Talent?")) return;
    setLoading(true);
    try {
        await upgradeUserToTalent(user.id);
        alert("Profilo aggiornato! Ricarica la pagina.");
        window.location.reload();
    } catch (e) {
        console.error(e);
        alert("Errore aggiornamento profilo.");
    } finally {
        setLoading(false);
    }
  };

  const handleCreateTestRequest = async () => {
    setLoading(true);
    try {
        await createRequest({
            talentId: user.id,
            fanId: user.id,
            fanName: "Test User",
            recipientName: "Me Stesso (Test)",
            instructions: "Test tecnico video upload.",
            occasion: "Test Tecnico",
            pricePaid: 0,
            isFastDelivery: false
        });
        await refreshData();
        alert("Richiesta di test creata!");
    } catch (e) {
        console.error(e);
        alert("Errore creazione richiesta test.");
    } finally {
        setLoading(false);
    }
  };

  // --- RECORDING LOGIC ---

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
      alert("Impossibile accedere alla videocamera. Verifica i permessi.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
  };

  const startRecording = () => {
    if (!stream) return;
    setRecordedChunks([]);
    const mediaRecorder = new MediaRecorder(stream);
    mediaRecorderRef.current = mediaRecorder;
    mediaRecorder.ondataavailable = (event) => {
      if (event.data.size > 0) setRecordedChunks((prev) => [...prev, event.data]);
    };
    mediaRecorder.start();
    setIsRecording(true);
    setRecordingTime(0);
    const interval = setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    mediaRecorder.onstop = () => {
        clearInterval(interval);
        setIsRecording(false);
    };
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
    }
  };

  useEffect(() => {
    if (!isRecording && recordedChunks.length > 0) {
      const blob = new Blob(recordedChunks, { type: 'video/webm' });
      setRecordedBlob(blob);
      const url = URL.createObjectURL(blob);
      setPreviewUrl(url);
      stopCamera();
    }
  }, [isRecording, recordedChunks]);

  const resetRecording = () => {
    setRecordedBlob(null);
    setPreviewUrl(null);
    setRecordedChunks([]);
    setRecordingTime(0);
    startCamera();
  };

  // --- SUBMISSION LOGIC (Updated with Watermark Processing) ---

  const handleSubmit = async () => {
    if (!selectedRequest) return;

    let rawFile: Blob | null = uploadMode === 'upload' ? uploadFile : recordedBlob;
    if (!rawFile) return;

    setIsSubmitting(true);
    setProcessingStatus('Preparazione video...');

    try {
        let finalFile = rawFile;
        let finalType = rawFile.type || 'video/mp4'; 

        // 1. Processing Watermark
        if (adminSettings?.watermarkUrl) {
            setProcessingStatus('Applicazione filigrana in corso (potrebbe richiedere qualche secondo)...');
            try {
                const fileObj = rawFile instanceof File ? rawFile : new File([rawFile], "recorded.webm", { type: rawFile.type || 'video/webm' });
                const result = await addWatermarkToVideo(fileObj, adminSettings.watermarkUrl);
                finalFile = result.blob;
                finalType = result.extension === 'mp4' ? 'video/mp4' : 'video/webm';
                console.log("Watermark applicato correttamente.");
            } catch (err: any) {
                console.error("Errore applicazione watermark:", err);
                const errorMsg = err.message || "Errore Sconosciuto";

                // Messaggio Utente Migliorato
                let userFriendlyError = `Filigrana non applicata. Caricamento video originale...`;
                if (errorMsg.includes("CORS")) {
                    userFriendlyError = `Filigrana non valida (Errore CORS). Per favore RICARICA la filigrana nel pannello Admin per risolvere. Caricamento originale...`;
                }

                setProcessingStatus(userFriendlyError);
                await new Promise(r => setTimeout(r, 2500)); // Pausa più lunga per leggere
            }
        }

        // 2. Upload
        setProcessingStatus('Caricamento su server...');
        const uploadBlob = finalFile.slice(0, finalFile.size, finalType);
        await uploadVideo(uploadBlob, selectedRequest.id);

        closeModal();
        refreshData();
    } catch (error: any) {
        console.error("Errore upload:", error);
        alert(error.message || "Errore durante il caricamento del video.");
    } finally {
        setIsSubmitting(false);
        setProcessingStatus('');
    }
  };

  const closeModal = () => {
    setSelectedRequest(null);
    setUploadFile(null);
    setRecordedBlob(null);
    setPreviewUrl(null);
    setRecordedChunks([]);
    setIsSubmitting(false);
    setProcessingStatus('');
    stopCamera();
  };

  const openModal = (req: VideoRequest) => {
      setSelectedRequest(req);
      setUploadMode('upload');
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getStatusBadge = (status: RequestStatus) => {
    switch(status) {
        case RequestStatus.PENDING: return <span className="bg-amber-100 text-amber-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-amber-200"><Clock className="w-3 h-3 mr-1"/> In attesa</span>;
        case RequestStatus.IN_REVIEW: return <span className="bg-blue-100 text-blue-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-blue-200"><Hourglass className="w-3 h-3 mr-1"/> Revisione Fan</span>;
        case RequestStatus.COMPLETED: return <span className="bg-emerald-100 text-emerald-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-emerald-200"><CheckCircle className="w-3 h-3 mr-1"/> Completato</span>;
        case RequestStatus.DISPUTE_OPEN: return <span className="bg-red-100 text-red-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-red-200"><AlertTriangle className="w-3 h-3 mr-1"/> Contestazione</span>;
        case RequestStatus.CORRECTION_NEEDED: return <span className="bg-orange-100 text-orange-800 text-xs px-2 py-1 rounded-full flex items-center w-fit border border-orange-200"><RefreshCw className="w-3 h-3 mr-1"/> Correzione Richiesta</span>;
        case RequestStatus.EXPIRED: return <span className="bg-gray-200 text-gray-600 text-xs px-2 py-1 rounded-full flex items-center w-fit"><Clock className="w-3 h-3 mr-1"/> Scaduto</span>;
        case RequestStatus.CANCELED_BY_FAN: return <span className="bg-gray-200 text-gray-600 text-xs px-2 py-1 rounded-full flex items-center w-fit"><XCircle className="w-3 h-3 mr-1"/> Annullato</span>;
        default: return <span className="bg-gray-100 text-gray-800 text-xs px-2 py-1 rounded-full">{status}</span>;
    }
  };

  if (loading) return <div className="flex justify-center p-12"><Loader2 className="animate-spin text-slate-900 h-8 w-8" /></div>;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <h1 className="text-3xl font-bold text-slate-900">
          {user.role === UserRole.FAN ? 'Le tue richieste' : `Ciao, ${user.name}`}
        </h1>

        <div className="flex items-center gap-3 w-full md:w-auto flex-wrap">
            <button 
                onClick={refreshData}
                className="bg-white border border-gray-200 text-gray-700 hover:bg-gray-50 hover:text-slate-900 px-4 py-2 rounded-lg text-sm font-medium shadow-sm transition-all flex items-center justify-center"
                title="Ricarica i dati della dashboard"
            >
                <RefreshCw className="w-4 h-4 mr-2" />
                Aggiorna
            </button>

            {user.role === UserRole.TALENT && (
            <div className="flex space-x-2 bg-white p-1 rounded-lg border border-gray-200 shadow-sm ml-auto md:ml-0">
                <button 
                onClick={() => setActiveTab('requests')}
                className={`px-4 py-2 rounded-md text-sm font-medium transition-colors flex items-center ${activeTab === 'requests' ? 'bg-slate-900 text-white shadow-md' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                <VideoIcon className="w-4 h-4 mr-2"/> <span className="hidden sm:inline">Richieste</span>
                </button>
                <button 
                onClick={() => setActiveTab('wallet')}
                className={`px-4 py-2 rounded-md text-sm font-medium transition-colors flex items-center ${activeTab === 'wallet' ? 'bg-slate-900 text-white shadow-md' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                <Wallet className="w-4 h-4 mr-2"/> <span className="hidden sm:inline">Guadagni</span>
                </button>
            </div>
            )}
        </div>
      </div>

      {user.role === UserRole.TALENT && activeTab === 'wallet' ? (
        <div className="space-y-6">
           {/* Wallet UI Code */}
           <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
             <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                <div className="flex items-center justify-between mb-2">
                   <h3 className="text-sm font-medium text-gray-500">Saldo Disponibile</h3>
                   <DollarSign className="w-5 h-5 text-emerald-600 bg-emerald-100 rounded-full p-1"/>
                </div>
                <p className="text-3xl font-bold text-slate-900">€{walletData.balance.toFixed(2)}</p>
                <p className="text-xs text-gray-500 mt-1">Prossimo pagamento: {walletData.nextPayout}</p>
             </div>
             <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                <div className="flex items-center justify-between mb-2">
                   <h3 className="text-sm font-medium text-gray-500">In Sospeso</h3>
                   <TrendingUp className="w-5 h-5 text-amber-600 bg-amber-100 rounded-full p-1"/>
                </div>
                <p className="text-3xl font-bold text-slate-900">€{walletData.pending.toFixed(2)}</p>
                <p className="text-xs text-gray-500 mt-1">Video in revisione o non completati</p>
             </div>
             <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
                <div className="flex items-center justify-between mb-2">
                   <h3 className="text-sm font-medium text-gray-500">Totale Guadagnato</h3>
                   <Wallet className="w-5 h-5 text-blue-600 bg-blue-100 rounded-full p-1"/>
                </div>
                <p className="text-3xl font-bold text-slate-900">€{walletData.totalEarned.toFixed(2)}</p>
                <p className="text-xs text-gray-500 mt-1">Dall'inizio della tua attività</p>
             </div>
           </div>

           <div className="bg-slate-900 rounded-xl p-6 text-white shadow-lg flex flex-col md:flex-row items-center justify-between">
              <div className="mb-4 md:mb-0">
                  <h3 className="text-lg font-bold mb-1">Stripe Connect</h3>
                  <p className="text-slate-300 text-sm">Gestisci i tuoi metodi di pagamento e vedi i dettagli delle transazioni su Stripe.</p>
              </div>
              <button className="bg-white text-slate-900 px-5 py-2.5 rounded-lg font-bold text-sm hover:bg-gray-100 transition-colors flex items-center">
                  <CreditCard className="w-4 h-4 mr-2" />
                  Dashboard Stripe
              </button>
           </div>
        </div>
      ) : (
        /* Requests View */
        requests.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-xl border border-gray-200 border-dashed">
            <VideoIcon className="mx-auto h-12 w-12 text-gray-300" />
            <h3 className="mt-4 text-sm font-medium text-slate-900">Nessuna richiesta</h3>
            <p className="mt-1 text-sm text-gray-500">
              {user.role === UserRole.FAN ? 'Non hai ancora richiesto nessun video.' : 'Nessun fan ti ha ancora scritto.'}
            </p>
          </div>
        ) : (
          <div className="grid gap-6">
            {requests.map(req => {
                const refundState = getRefundState(req);
                const isLockedForTalent = req.status === RequestStatus.PENDING && refundState.isActive;
                const adminMsg = user.role === UserRole.FAN ? req.adminNoteFan : req.adminNoteTalent;

                return (
              <div key={req.id} className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col md:flex-row gap-8">
                <div className="flex-1">
                  {/* Header Card */}
                  <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center">
                        <div className="h-10 w-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 font-bold mr-3">
                            {user.role === UserRole.FAN ? req.talentId.substring(0,2).toUpperCase() : req.fanName.substring(0,2).toUpperCase()}
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-slate-900">
                                {user.role === UserRole.FAN ? `Per: ${req.recipientName}` : `Da: ${req.fanName}`}
                            </h3>
                            <p className="text-xs text-gray-500">ID: {req.id.substring(0,8)}</p>
                        </div>
                      </div>
                      <div className="flex flex-col items-end">
                          {getStatusBadge(req.status)}
                          {user.role === UserRole.FAN && req.status === RequestStatus.PENDING && refundState.isActive && (
                              <button 
                                  onClick={() => handleCancelOrder(req.id)}
                                  className="mt-2 text-xs text-red-600 hover:text-red-800 underline font-medium"
                              >
                                  Annulla Ordine ({refundState.minsLeft}m rimasti)
                              </button>
                          )}
                          {user.role === UserRole.TALENT && req.status === RequestStatus.PENDING && !isLockedForTalent && (req.expiresAt || req.expirationTimestamp) && (
                              <div className={`mt-2 text-xs px-2 py-1 rounded-md font-bold flex items-center ${getUrgencyColor(req)}`}>
                                  <CalendarClock className="w-3 h-3 mr-1" />
                                  Consegna: {getDeadlineCountdown(req)}
                              </div>
                          )}
                      </div>
                  </div>

                  {/* Dettagli Istruzioni */}
                  <p className="text-sm text-gray-500 mb-4 flex items-center">
                    <span className="font-semibold text-slate-700 mr-2">Occasione:</span> {req.occasion}
                  </p>
                  <div className="bg-gray-50 p-5 rounded-lg mb-4 border border-gray-100">
                      <p className="text-xs text-gray-400 uppercase tracking-wide font-bold mb-2">Istruzioni</p>
                      <p className="text-slate-700 text-sm italic leading-relaxed">"{req.instructions}"</p>
                  </div>

                  {/* Messaggio Admin */}
                  {adminMsg && (req.status === RequestStatus.CORRECTION_NEEDED || req.status === RequestStatus.COMPLETED) && (
                      <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 mb-4 animate-fadeIn">
                          <h4 className="text-xs font-bold text-blue-800 uppercase tracking-wider mb-1 flex items-center">
                              <Info className="w-3 h-3 mr-1" /> Messaggio dall'Admin
                          </h4>
                          <p className="text-sm text-blue-900">{adminMsg}</p>
                      </div>
                  )}

                  {/* VIDEO PLAYER SECTION */}
                  {(req.status === RequestStatus.COMPLETED || req.status === RequestStatus.IN_REVIEW || req.status === RequestStatus.DISPUTE_OPEN || req.status === RequestStatus.CORRECTION_NEEDED) && req.videoUrl && (
                      <div className="mt-6">
                          <VideoPlayer 
                              src={req.videoUrl} 
                              watermarkUrl={adminSettings?.watermarkUrl}
                          />

                          {/* FAN REVIEW SECTION */}
                          {req.status === RequestStatus.IN_REVIEW && user.role === UserRole.FAN && (
                              <div className="bg-amber-50 rounded-xl p-5 border border-amber-200 mt-2 animate-fadeIn">
                                  <div className="flex items-center mb-3">
                                      <AlertTriangle className="w-5 h-5 text-amber-600 mr-2" />
                                      <h4 className="font-bold text-slate-800">Azione Richiesta: Revisione Video</h4>
                                  </div>
                                  <p className="text-sm text-slate-600 mb-4">
                                      Hai ricevuto il tuo video! Controllalo e facci sapere se va tutto bene.
                                      <br/>
                                      <span className="font-bold text-amber-700">Hai ancora {getDisputeTimeLeft(req)} ore per segnalare problemi.</span>
                                  </p>
                                  <div className="flex gap-3">
                                      <button 
                                          onClick={() => handleCompleteOrder(req)}
                                          className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white py-2.5 px-4 rounded-lg font-bold text-sm shadow-md flex items-center justify-center transition-all transform hover:-translate-y-0.5"
                                      >
                                          <CheckCircle className="w-4 h-4 mr-2" />
                                          Accetta e Completa
                                      </button>
                                      <button 
                                          onClick={() => handleOpenDisputeModal(req)}
                                          className="flex-1 bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 py-2.5 px-4 rounded-lg font-bold text-sm shadow-sm flex items-center justify-center"
                                      >
                                          <AlertTriangle className="w-4 h-4 mr-2" />
                                          Segnala Problema
                                      </button>
                                  </div>
                              </div>
                          )}

                          {/* STATUS INFO MESSAGES */}
                          {req.status === RequestStatus.DISPUTE_OPEN && (
                               <div className="bg-red-50 p-4 rounded-lg mt-4 border border-red-100">
                                   <p className="text-red-800 font-bold text-sm flex items-center">
                                       <AlertTriangle className="w-4 h-4 mr-2" /> Contestazione Aperta
                                   </p>
                               </div>
                          )}
                          {req.status === RequestStatus.CORRECTION_NEEDED && (
                               <div className="bg-orange-50 p-4 rounded-lg mt-4 border border-orange-100">
                                   <p className="text-orange-800 font-bold text-sm flex items-center">
                                       <RefreshCw className="w-4 h-4 mr-2" /> Correzione Richiesta
                                   </p>
                               </div>
                          )}
                      </div>
                  )}
                </div>

                {/* Talent Sidebar */}
                {user.role === UserRole.TALENT && (
                    <div className="md:w-72 flex flex-col space-y-3 border-t md:border-t-0 md:border-l border-gray-100 pt-6 md:pt-0 md:pl-8 justify-center">
                        {(req.status === RequestStatus.PENDING || req.status === RequestStatus.CORRECTION_NEEDED) && (
                            <>
                                {isLockedForTalent ? (
                                    <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-3 text-center mb-2">
                                        <Lock className="w-5 h-5 text-yellow-600 mx-auto mb-1" />
                                        <p className="text-xs text-yellow-800 font-bold mb-1">Upload Bloccato</p>
                                    </div>
                                ) : (
                                    <button
                                    onClick={() => openModal(req)}
                                    className="w-full bg-slate-900 hover:bg-black text-white py-3 px-4 rounded-lg text-sm font-bold flex items-center justify-center transition-all shadow-md hover:shadow-lg transform hover:-translate-y-0.5"
                                    >
                                    <VideoIcon className="w-4 h-4 mr-2" />
                                    {req.status === RequestStatus.CORRECTION_NEEDED ? "Carica Correzione" : "Registra Risposta"}
                                    </button>
                                )}

                                {req.status === RequestStatus.PENDING && (
                                    <button 
                                        onClick={() => handleRejectRequest(req.id)}
                                        className="w-full bg-white border border-gray-200 text-gray-600 hover:bg-red-50 hover:text-red-600 hover:border-red-200 py-3 px-4 rounded-lg text-sm font-medium transition-colors"
                                    >
                                        Rifiuta Richiesta
                                    </button>
                                )}
                            </>
                        )}
                        {req.status === RequestStatus.IN_REVIEW && (
                             <div className="flex flex-col gap-2">
                                 <button
                                    onClick={() => openModal(req)}
                                    className="w-full bg-white border border-slate-300 text-slate-700 hover:bg-slate-50 py-2 px-4 rounded-lg text-sm font-bold flex items-center justify-center shadow-sm"
                                 >
                                    <RefreshCw className="w-3 h-3 mr-2" />
                                    Sostituisci Video
                                 </button>
                                 <button
                                    onClick={() => handleDeleteVideo(req)}
                                    className="w-full bg-white border border-red-200 text-red-600 hover:bg-red-50 py-2 px-4 rounded-lg text-sm font-medium flex items-center justify-center"
                                 >
                                    <Trash2 className="w-3 h-3 mr-2" />
                                    Elimina Video
                                 </button>
                             </div>
                        )}
                    </div>
                )}
              </div>
            );
            })}
          </div>
        )
      )}

      {/* DEVELOPER ZONE */}
      <div className="mt-16 border-t border-gray-200 pt-8">
        <div className="bg-slate-50 rounded-lg p-4 border border-slate-200">
            <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 flex items-center">
                <Wrench className="w-3 h-3 mr-1" />
                Developer Zone (Solo per test)
            </h4>
            <div className="flex gap-4">
                {user.role === UserRole.FAN && (
                    <button 
                        onClick={handleBecomeTalent}
                        className="text-xs bg-white border border-slate-300 hover:bg-slate-100 text-slate-700 px-3 py-2 rounded font-medium transition-colors shadow-sm"
                    >
                        ⚡ Diventa Talent (Demo)
                    </button>
                )}
                {user.role === UserRole.TALENT && (
                    <button 
                        onClick={handleCreateTestRequest}
                        className="text-xs bg-white border border-slate-300 hover:bg-slate-100 text-slate-700 px-3 py-2 rounded font-medium transition-colors shadow-sm"
                    >
                        🧪 Crea Richiesta di Prova
                    </button>
                )}
            </div>
        </div>
      </div>

      {/* DISPUTE MODAL */}
      {disputeModalOpen && (
           <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
               <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full p-8">
                   <h3 className="text-xl font-bold text-red-600 mb-4 flex items-center">
                       <AlertTriangle className="w-6 h-6 mr-2" /> Apri Contestazione
                   </h3>
                   <textarea 
                       className="w-full border border-gray-300 rounded-lg p-3 text-sm mb-4"
                       rows={4}
                       placeholder="Descrivi il problema..."
                       value={disputeReason}
                       onChange={(e) => setDisputeReason(e.target.value)}
                   ></textarea>
                   <div className="flex justify-end gap-3">
                       <button onClick={() => setDisputeModalOpen(false)} className="px-4 py-2 text-gray-600">Annulla</button>
                       <button onClick={submitDispute} className="px-4 py-2 bg-red-600 text-white rounded-lg">Invia</button>
                   </div>
               </div>
           </div>
      )}

      {/* UPLOAD MODAL */}
      {selectedRequest && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full p-8 max-h-[95vh] overflow-y-auto">
                <div className="flex justify-between items-center mb-6">
                     <h3 className="text-2xl font-bold text-slate-900">Rispondi a {selectedRequest.fanName}</h3>
                     <button onClick={closeModal} className="text-gray-400 hover:text-slate-900"><XCircle className="w-6 h-6"/></button>
                </div>

                {/* Tabs */}
                <div className="flex border-b border-gray-200 mb-8">
                    <button 
                        className={`flex-1 pb-4 text-sm font-bold transition-all ${uploadMode === 'upload' ? 'text-slate-900 border-b-2 border-slate-900' : 'text-gray-400 hover:text-gray-600'}`}
                        onClick={() => { setUploadMode('upload'); stopCamera(); }}
                    >
                        <div className="flex items-center justify-center"><Upload className="w-4 h-4 mr-2" /> Carica File</div>
                    </button>
                    <button 
                        className={`flex-1 pb-4 text-sm font-bold transition-all ${uploadMode === 'record' ? 'text-slate-900 border-b-2 border-slate-900' : 'text-gray-400 hover:text-gray-600'}`}
                        onClick={() => { setUploadMode('record'); startCamera(); }}
                    >
                        <div className="flex items-center justify-center"><Camera className="w-4 h-4 mr-2" /> Registra Ora</div>
                    </button>
                </div>

                {/* Content */}
                {uploadMode === 'upload' && (
                    <div className="mb-8">
                        <div className="border-2 border-dashed border-gray-300 rounded-2xl p-10 text-center hover:border-slate-500 transition-colors bg-gray-50">
                            <input 
                                type="file" 
                                accept="video/*" 
                                onChange={(e) => setUploadFile(e.target.files ? e.target.files[0] : null)}
                                className="hidden" 
                                id="video-upload"
                            />
                            <label htmlFor="video-upload" className="cursor-pointer flex flex-col items-center">
                                {uploadFile ? (
                                    <>
                                        <CheckCircle className="h-12 w-12 text-emerald-500 mb-3" />
                                        <span className="text-lg text-slate-900 font-bold">{uploadFile.name}</span>
                                        <span className="text-sm text-gray-500 mt-2">Clicca per cambiare file</span>
                                    </>
                                ) : (
                                    <>
                                        <Upload className="h-12 w-12 text-gray-300 mb-3" />
                                        <span className="text-base text-slate-700 font-medium">Trascina qui o clicca per selezionare</span>
                                    </>
                                )}
                            </label>
                        </div>
                    </div>
                )}

                {/* Record UI */}
                {uploadMode === 'record' && (
                    <div className="mb-8">
                        <div className="bg-black rounded-2xl aspect-video relative overflow-hidden flex items-center justify-center shadow-inner">
                            {!previewUrl ? (
                                <>
                                    <video ref={videoRef} autoPlay muted playsInline className={`w-full h-full object-cover transform scale-x-[-1] ${!stream ? 'hidden' : ''}`} />
                                    {!stream && <div className="text-white"><p>Avvio fotocamera...</p></div>}
                                    {isRecording && (
                                        <div className="absolute top-4 right-4 bg-red-600 text-white text-xs font-bold px-3 py-1.5 rounded-full animate-pulse">REC {formatTime(recordingTime)}</div>
                                    )}
                                    <div className="absolute bottom-6 left-0 right-0 flex justify-center space-x-6">
                                        {!isRecording ? (
                                            <button onClick={startRecording} disabled={!stream} className="bg-red-600 hover:bg-red-700 text-white rounded-full p-5 shadow-2xl border-4 border-white/20"><div className="w-4 h-4 bg-white rounded-sm"></div></button>
                                        ) : (
                                            <button onClick={stopRecording} className="bg-slate-800 hover:bg-slate-900 text-white rounded-full p-5 shadow-2xl border-4 border-white"><StopCircle className="w-6 h-6" /></button>
                                        )}
                                    </div>
                                </>
                            ) : (
                                <>
                                    <video controls className="w-full h-full object-contain" src={previewUrl} />
                                    <button onClick={resetRecording} className="absolute top-4 right-4 bg-black/60 text-white p-2.5 rounded-full"><RefreshCw className="w-5 h-5" /></button>
                                </>
                            )}
                        </div>
                    </div>
                )}

                {isSubmitting && processingStatus && (
                    <div className="mb-4 bg-blue-50 text-blue-800 p-3 rounded-lg text-sm flex items-center animate-pulse border border-blue-100">
                        <Loader2 className="animate-spin w-4 h-4 mr-2" />
                        {processingStatus}
                    </div>
                )}

                <div className="flex space-x-4 pt-4 border-t border-gray-100">
                    <button onClick={closeModal} className="flex-1 py-3.5 border border-gray-300 rounded-xl font-bold hover:bg-gray-50">Annulla</button>
                    <button 
                        onClick={handleSubmit}
                        disabled={ (uploadMode === 'upload' && !uploadFile) || (uploadMode === 'record' && !recordedBlob) || isSubmitting }
                        className="flex-1 py-3.5 bg-slate-900 text-white rounded-xl font-bold hover:bg-black disabled:opacity-50 flex justify-center items-center"
                    >
                        {isSubmitting ? <Loader2 className="animate-spin h-5 w-5" /> : 'Invia Video'}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import TalentProfile from './pages/TalentProfile';
import Dashboard from './pages/Dashboard';
import Login from './pages/Login';
import AdminDashboard from './pages/AdminDashboard';
import { User, UserRole, AdminSettings } from './types';
import { auth } from './firebaseConfig';
import * as firebaseAuth from 'firebase/auth';
import { syncUserToDB, getAdminSettings, acceptNewTerms } from './services/dataService';
import { Loader2, AlertTriangle, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [adminSettings, setAdminSettings] = useState<AdminSettings | null>(null);

  useEffect(() => {
    const unsubscribe = firebaseAuth.onAuthStateChanged(auth, async (firebaseUser) => {
      const settings = await getAdminSettings();
      setAdminSettings(settings);

      if (firebaseUser) {
        // Fix User object to satisfy interface requirements
        const dbUser = await syncUserToDB({ 
          id: firebaseUser.uid, 
          email: firebaseUser.email || '', 
          name: firebaseUser.displayName || 'Utente',
          role: UserRole.FAN, // Temporary, syncUserToDB handles actual role
          lastAcceptedTermsVersion: 0
        });
        setUser(dbUser);
      } else {
        setUser(null);
      }
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  const handleAcceptTerms = async () => {
    if (!user || !adminSettings) return;
    await acceptNewTerms(user.id, adminSettings.termsVersion);
    setUser({ ...user, lastAcceptedTermsVersion: adminSettings.termsVersion });
  };

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin" /></div>;

  // BLOCKING MODAL LOGIC (VIP ONLY)
  const needsTermsUpdate = user?.role === UserRole.TALENT && adminSettings && user.lastAcceptedTermsVersion < adminSettings.termsVersion;

  return (
    <Router>
      <div className="min-h-screen bg-gray-50 flex flex-col">
        <Navbar user={user} onLogout={() => firebaseAuth.signOut(auth)} />

        {needsTermsUpdate && (
            <div className="fixed inset-0 z-[9999] bg-slate-900/90 backdrop-blur-md flex items-center justify-center p-4">
                <div className="bg-white rounded-3xl p-8 max-w-md w-full shadow-2xl text-center">
                    <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-6">
                        <ShieldCheck className="w-8 h-8" />
                    </div>
                    <h2 className="text-2xl font-black text-slate-900 mb-4 uppercase">Regolamento Aggiornato</h2>
                    <p className="text-slate-600 mb-8">
                        Abbiamo aggiornato i termini di servizio di CiaoStar per riflettere le nuove policy di consegna e gestione fiscale.
                    </p>
                    <button 
                        onClick={handleAcceptTerms}
                        className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-black transition-all"
                    >
                        ACCETTO I NUOVI TERMINI
                    </button>
                </div>
            </div>
        )}

        <main className="flex-1">
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={!user ? <Login onLogin={() => {}} /> : <Navigate to="/" />} />
              <Route path="/talent/:id" element={<TalentProfile currentUser={user} />} />
              <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
              <Route path="/admin" element={user?.role === UserRole.ADMIN ? <AdminDashboard user={user} /> : <Navigate to="/" />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { Talent, User } from '../types';
import { syncUserToDB, updateTalentProfile, getCategories, uploadAvatar } from '../services/dataService';
import { moderateText, generateCreativeBio } from '../services/geminiService';
import { Loader2, Save, DollarSign, Clock, Zap, AlertTriangle, Tag, ChevronDown, Camera, User as UserIcon, Wand2 } from 'lucide-react';

interface TalentSettingsProps {
    user: User;
}

const TalentSettings: React.FC<TalentSettingsProps> = ({ user }) => {
    const [talent, setTalent] = useState<Talent | null>(null);
    const [categories, setCategories] = useState<string[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    // Form State
    const [displayName, setDisplayName] = useState('');
    const [price, setPrice] = useState(0);
    const [category, setCategory] = useState('');
    const [bio, setBio] = useState('');
    const [isAvailable, setIsAvailable] = useState(true);
    const [fastDeliveryEnabled, setFastDeliveryEnabled] = useState(false);
    const [fastDeliveryIncrease, setFastDeliveryIncrease] = useState(20);
    const [responseTime, setResponseTime] = useState(3);

    // Change Detection State
    const [initialFormState, setInitialFormState] = useState<any>(null);
    const [hasChanges, setHasChanges] = useState(false);

    // AI State
    const [isGeneratingBio, setIsGeneratingBio] = useState(false);

    // Avatar State
    const [avatarFile, setAvatarFile] = useState<File | null>(null);
    const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
    const [uploadingAvatar, setUploadingAvatar] = useState(false);

    useEffect(() => {
        const loadData = async () => {
            setLoading(true);
            try {
                // Carica profilo e categorie dal DB in parallelo
                const [profileData, catsData] = await Promise.all([
                    syncUserToDB(user),
                    getCategories()
                ]);

                setCategories(catsData);

                // Cast to Talent safely
                if (profileData.role === 'TALENT') {
                    const t = profileData as Talent;
                    setTalent(t);

                    // Prepare initial values
                    const initialName = t.name || '';
                    const initialPrice = t.price || 0;
                    const initialBio = t.bio || '';
                    const initialAvail = t.isAvailable !== false;
                    const initialFastEnabled = t.fastDeliveryEnabled || false;
                    const initialFastIncrease = t.fastDeliveryPriceIncrease || 20;
                    const initialResponse = t.responseTimeDays || 3;

                    if (t.avatarUrl) setAvatarPreview(t.avatarUrl);

                    // Se la categoria attuale del talent non è nella lista DB (caso legacy), mantienila o usa la prima disponibile
                    const initialCategory = (t.category && catsData.includes(t.category)) 
                        ? t.category 
                        : catsData[0] || '';

                    // Set Form State
                    setDisplayName(initialName);
                    setPrice(initialPrice);
                    setBio(initialBio);
                    setCategory(initialCategory);
                    setIsAvailable(initialAvail);
                    setFastDeliveryEnabled(initialFastEnabled);
                    setFastDeliveryIncrease(initialFastIncrease);
                    setResponseTime(initialResponse);

                    // Set Initial State for Comparison
                    setInitialFormState({
                        displayName: initialName,
                        price: initialPrice,
                        bio: initialBio,
                        category: initialCategory,
                        isAvailable: initialAvail,
                        fastDeliveryEnabled: initialFastEnabled,
                        fastDeliveryIncrease: initialFastIncrease,
                        responseTime: initialResponse
                    });
                }
            } catch (e) {
                console.error("Errore caricamento impostazioni:", e);
            } finally {
                setLoading(false);
            }
        };
        loadData();
    }, [user]);

    // Check for changes effect
    useEffect(() => {
        if (!initialFormState) return;

        const isChanged = 
            displayName !== initialFormState.displayName ||
            price !== initialFormState.price ||
            category !== initialFormState.category ||
            bio !== initialFormState.bio ||
            isAvailable !== initialFormState.isAvailable ||
            fastDeliveryEnabled !== initialFormState.fastDeliveryEnabled ||
            fastDeliveryIncrease !== initialFormState.fastDeliveryIncrease ||
            responseTime !== initialFormState.responseTime ||
            avatarFile !== null;

        setHasChanges(isChanged);
    }, [
        displayName, price, category, bio, isAvailable, 
        fastDeliveryEnabled, fastDeliveryIncrease, responseTime, 
        avatarFile, initialFormState
    ]);

    const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];

            // Quality Check: Size < 5MB
            if (file.size > 5 * 1024 * 1024) {
                alert("L'immagine è troppo grande. Dimensione massima 5MB.");
                return;
            }
            // Quality Check: Type
            if (!file.type.startsWith('image/')) {
                alert("Per favore carica un file immagine valido.");
                return;
            }

            setAvatarFile(file);
            setAvatarPreview(URL.createObjectURL(file));
        }
    };

    const handleAiMagic = async () => {
        if (!category) {
            alert("Seleziona prima una categoria per aiutare l'AI.");
            return;
        }
        setIsGeneratingBio(true);
        const newBio = await generateCreativeBio(displayName || user.name, category, bio);
        setBio(newBio);
        setIsGeneratingBio(false);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        try {
            // 0. Validazione base
            if (!displayName.trim()) {
                alert("Il nome visualizzato non può essere vuoto.");
                setSaving(false);
                return;
            }

            // 1. Moderazione Nome con Gemini
            const nameCheck = await moderateText(displayName, 'name');
            if (!nameCheck.safe) {
                alert(`NOME NON VALIDO.\n\nIl nome scelto viola le linee guida:\n${nameCheck.reason}`);
                setSaving(false);
                return;
            }

            // 2. Moderazione Biografia con Gemini
            const bioCheck = await moderateText(bio, 'bio');
            if (!bioCheck.safe) {
                alert(`BIOGRAFIA NON VALIDA.\n\nIl testo viola le linee guida:\n${bioCheck.reason}`);
                setSaving(false);
                return;
            }

            // 3. Upload Avatar se cambiato
            let newAvatarUrl = talent?.avatarUrl;
            if (avatarFile) {
                setUploadingAvatar(true);
                newAvatarUrl = await uploadAvatar(avatarFile, user.id);
                setUploadingAvatar(false);
            }

            // 4. Update Firestore Profile
            await updateTalentProfile(user.id, {
                name: displayName,
                price: Number(price),
                category,
                bio,
                isAvailable,
                fastDeliveryEnabled,
                fastDeliveryPriceIncrease: Number(fastDeliveryIncrease),
                responseTimeDays: Number(responseTime),
                avatarUrl: newAvatarUrl
            });

            // Update initial state to match current (saved) state
            setInitialFormState({
                displayName,
                price: Number(price),
                category,
                bio,
                isAvailable,
                fastDeliveryEnabled,
                fastDeliveryIncrease: Number(fastDeliveryIncrease),
                responseTime: Number(responseTime)
            });
            setAvatarFile(null); // Clear pending file
            setHasChanges(false);

            alert("Profilo aggiornato con successo!");
        } catch (error) {
            console.error(error);
            alert("Errore durante il salvataggio.");
        } finally {
            setSaving(false);
            setUploadingAvatar(false);
        }
    };

    if (loading) return <div className="flex justify-center p-12"><Loader2 className="animate-spin text-slate-900 h-8 w-8" /></div>;
    if (!talent) return <div className="p-12 text-center">Devi essere un Talent per accedere a questa pagina.</div>;

    return (
        <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
            <h1 className="text-3xl font-bold text-slate-900 mb-2">Impostazioni Profilo</h1>
            <p className="text-gray-500 mb-8">Gestisci la tua disponibilità, i prezzi e le opzioni di consegna.</p>

            <form onSubmit={handleSave} className="space-y-8">

                {/* 0. Avatar & Bio */}
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                    <h2 className="text-lg font-bold text-slate-900 mb-6 flex items-center">
                        <UserIcon className="w-5 h-5 mr-2" /> Identità Pubblica
                    </h2>

                    <div className="flex flex-col items-center sm:flex-row gap-8 mb-6">
                        <div className="relative group cursor-pointer flex-shrink-0">
                            <div className="w-32 h-32 rounded-full overflow-hidden border-4 border-gray-100 bg-gray-200">
                                {avatarPreview ? (
                                    <img src={avatarPreview} alt="Avatar" className="w-full h-full object-cover" />
                                ) : (
                                    <div className="w-full h-full flex items-center justify-center text-gray-400">
                                        <UserIcon className="w-12 h-12" />
                                    </div>
                                )}
                            </div>
                            <div className="absolute inset-0 bg-black/40 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                <Camera className="w-8 h-8 text-white" />
                            </div>
                            <input 
                                type="file" 
                                className="absolute inset-0 opacity-0 cursor-pointer"
                                accept="image/*"
                                onChange={handleAvatarChange}
                            />
                        </div>
                        <div className="flex-1 w-full space-y-4">
                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-2">Nome Visualizzato</label>
                                <input
                                    type="text"
                                    value={displayName}
                                    onChange={(e) => setDisplayName(e.target.value)}
                                    className="block w-full rounded-lg border-gray-300 shadow-sm focus:border-slate-500 focus:ring-slate-500 sm:text-sm p-3 border"
                                    placeholder="Es. Mago Merlino"
                                    maxLength={30}
                                />
                            </div>

                            <div className="relative">
                                <label className="block text-sm font-semibold text-slate-700 mb-2 flex justify-between">
                                    <span>Biografia</span>
                                    <button
                                        type="button"
                                        onClick={handleAiMagic}
                                        disabled={isGeneratingBio}
                                        className="text-purple-600 hover:text-purple-800 text-xs font-bold flex items-center transition-colors disabled:opacity-50"
                                    >
                                        {isGeneratingBio ? <Loader2 className="w-3 h-3 animate-spin mr-1"/> : <Wand2 className="w-3 h-3 mr-1" />}
                                        AI Magic
                                    </button>
                                </label>
                                <textarea
                                    rows={4}
                                    value={bio}
                                    onChange={(e) => setBio(e.target.value)}
                                    className="block w-full rounded-lg border-gray-300 shadow-sm focus:border-slate-500 focus:ring-slate-500 sm:text-sm p-3 border"
                                    placeholder="Racconta chi sei ai tuoi fan..."
                                />
