                                  <div className="flex items-center mb-3">
                                      <AlertTriangle className="w-5 h-5 text-amber-600 mr-2" />
                                      <h4 className="font-bold text-slate-800">Azione Richiesta: Revisione Video</h4>
                                  </div>
                                  <p className="text-sm text-slate-600 mb-4">
                                      Hai ricevuto il tuo video! Controllalo e facci sapere se va tutto bene.
                                      <br/>
                                      <span className="font-bold text-amber-700">Hai ancora {getDisputeTimeLeft(req)} ore per segnalare problemi.</span>
                                  </p>
                                  <div className="flex gap-3">
                                      <button 
                                          onClick={() => handleCompleteOrder(req)}
                                          className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white py-2.5 px-4 rounded-lg font-bold text-sm shadow-md flex items-center justify-center transition-all transform hover:-translate-y-0.5"
                                      >
                                          <CheckCircle className="w-4 h-4 mr-2" />
                                          Accetta e Completa
                                      </button>
                                      <button 
                                          onClick={() => handleOpenDisputeModal(req)}
                                          className="flex-1 bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 py-2.5 px-4 rounded-lg font-bold text-sm shadow-sm flex items-center justify-center"
