                        {req.status === RequestStatus.IN_REVIEW && (
                             <div className="flex flex-col gap-2">
                                 <button
                                    onClick={() => openModal(req)}
                                    className="w-full bg-white border border-slate-300 text-slate-700 hover:bg-slate-50 py-2 px-4 rounded-lg text-sm font-bold flex items-center justify-center shadow-sm"
                                 >
                                    <RefreshCw className="w-3 h-3 mr-2" />
                                    Sostituisci Video
                                 </button>
                                 <button
                                    onClick={() => handleDeleteVideo(req)}
                                    className="w-full bg-white border border-red-200 text-red-600 hover:bg-red-50 py-2 px-4 rounded-lg text-sm font-medium flex items-center justify-center"
