                                    <Trash2 className="w-3 h-3 mr-2" />
                                    Elimina Video
                                 </button>
                             </div>
                        )}
                    </div>
                )}
              </div>
            );
            })}
          </div>
        )
      )}

      {/* DEVELOPER ZONE */}
      <div className="mt-16 border-t border-gray-200 pt-8">
        <div className="bg-slate-50 rounded-lg p-4 border border-slate-200">
            <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 flex items-center">
                <Wrench className="w-3 h-3 mr-1" />
                Developer Zone (Solo per test)
            </h4>
            <div className="flex gap-4">
                {user.role === UserRole.FAN && (
                    <button 
                        onClick={handleBecomeTalent}
                        className="text-xs bg-white border border-slate-300 hover:bg-slate-100 text-slate-700 px-3 py-2 rounded font-medium transition-colors shadow-sm"
                    >
                        ⚡ Diventa Talent (Demo)
                    </button>
                )}
                {user.role === UserRole.TALENT && (
                    <button 
                        onClick={handleCreateTestRequest}
                        className="text-xs bg-white border border-slate-300 hover:bg-slate-100 text-slate-700 px-3 py-2 rounded font-medium transition-colors shadow-sm"
                    >
                        🧪 Crea Richiesta di Prova
                    </button>
                )}
            </div>
        </div>
      </div>

      {/* DISPUTE MODAL */}
      {disputeModalOpen && (
           <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
               <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full p-8">
                   <h3 className="text-xl font-bold text-red-600 mb-4 flex items-center">
                       <AlertTriangle className="w-6 h-6 mr-2" /> Apri Contestazione
                   </h3>
                   <textarea 
                       className="w-full border border-gray-300 rounded-lg p-3 text-sm mb-4"
                       rows={4}
                       placeholder="Descrivi il problema..."
                       value={disputeReason}
                       onChange={(e) => setDisputeReason(e.target.value)}
                   ></textarea>
                   <div className="flex justify-end gap-3">
                       <button onClick={() => setDisputeModalOpen(false)} className="px-4 py-2 text-gray-600">Annulla</button>
                       <button onClick={submitDispute} className="px-4 py-2 bg-red-600 text-white rounded-lg">Invia</button>
                   </div>
               </div>
           </div>
      )}

      {/* UPLOAD MODAL */}
      {selectedRequest && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full p-8 max-h-[95vh] overflow-y-auto">
                <div className="flex justify-between items-center mb-6">
                     <h3 className="text-2xl font-bold text-slate-900">Rispondi a {selectedRequest.fanName}</h3>
                     <button onClick={closeModal} className="text-gray-400 hover:text-slate-900"><XCircle className="w-6 h-6"/></button>
                </div>

                {/* Tabs */}
                <div className="flex border-b border-gray-200 mb-8">
                    <button 
                        className={`flex-1 pb-4 text-sm font-bold transition-all ${uploadMode === 'upload' ? 'text-slate-900 border-b-2 border-slate-900' : 'text-gray-400 hover:text-gray-600'}`}
                        onClick={() => { setUploadMode('upload'); stopCamera(); }}
                    >
                        <div className="flex items-center justify-center"><Upload className="w-4 h-4 mr-2" /> Carica File</div>
                    </button>
                    <button 
                        className={`flex-1 pb-4 text-sm font-bold transition-all ${uploadMode === 'record' ? 'text-slate-900 border-b-2 border-slate-900' : 'text-gray-400 hover:text-gray-600'}`}
                        onClick={() => { setUploadMode('record'); startCamera(); }}
                    >
                        <div className="flex items-center justify-center"><Camera className="w-4 h-4 mr-2" /> Registra Ora</div>
                    </button>
                </div>

                {/* Content */}
                {uploadMode === 'upload' && (
                    <div className="mb-8">
                        {/* Warning Anti-AI */}
                        <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 mb-6 flex items-start">
                            <AlertTriangle className="w-5 h-5 text-amber-600 mr-3 flex-shrink-0 mt-0.5" />
                            <p className="text-sm text-amber-800 leading-relaxed">
                                <strong>Importante:</strong> Per garantire l'autenticità, registra il video direttamente dalla fotocamera. L'uso di contenuti clonati o generati da AI è severamente vietato e comporta il <strong>ban immediato</strong> e la perdita dei guadagni.
                            </p>
                        </div>

                        <div className="border-2 border-dashed border-gray-300 rounded-2xl p-10 text-center hover:border-slate-500 transition-colors bg-gray-50">
                            <input 
                                type="file" 
                                accept="video/*" 
                                capture="user"
                                onChange={(e) => setUploadFile(e.target.files ? e.target.files[0] : null)}
                                className="hidden" 
                                id="video-upload"
                            />
                            <label htmlFor="video-upload" className="cursor-pointer flex flex-col items-center">
                                {uploadFile ? (
                                    <>
                                        <CheckCircle className="h-12 w-12 text-emerald-500 mb-3" />
                                        <span className="text-lg text-slate-900 font-bold">{uploadFile.name}</span>
                                        <span className="text-sm text-gray-500 mt-2">Clicca per cambiare file</span>
                                    </>
                                ) : (
                                    <>
                                        <Camera className="h-12 w-12 text-gray-300 mb-3" />
                                        <span className="text-base text-slate-700 font-medium italic">Registra dalla fotocamera (Consigliato)</span>
                                        <span className="text-xs text-gray-400 mt-2">Oppure seleziona un file esistente</span>
                                    </>
                                )}
                            </label>
                        </div>
                    </div>
                )}

                {/* Record UI */}
                {uploadMode === 'record' && (
                    <div className="mb-8">
                        <div className="bg-black rounded-2xl aspect-video relative overflow-hidden flex items-center justify-center shadow-inner">
                            {!previewUrl ? (
                                <>
                                    <video ref={videoRef} autoPlay muted playsInline className={`w-full h-full object-cover transform scale-x-[-1] ${!stream ? 'hidden' : ''}`} />
                                    {!stream && <div className="text-white"><p>Avvio fotocamera...</p></div>}
                                    {isRecording && (
                                        <div className="absolute top-4 right-4 bg-red-600 text-white text-xs font-bold px-3 py-1.5 rounded-full animate-pulse">REC {formatTime(recordingTime)}</div>
                                    )}
                                    <div className="absolute bottom-6 left-0 right-0 flex justify-center space-x-6">
                                        {!isRecording ? (
                                            <button onClick={startRecording} disabled={!stream} className="bg-red-600 hover:bg-red-700 text-white rounded-full p-5 shadow-2xl border-4 border-white/20"><div className="w-4 h-4 bg-white rounded-sm"></div></button>
                                        ) : (
                                            <button onClick={stopRecording} className="bg-slate-800 hover:bg-slate-900 text-white rounded-full p-5 shadow-2xl border-4 border-white"><StopCircle className="w-6 h-6" /></button>
                                        )}
                                    </div>
                                </>
                            ) : (
                                <>
                                    <video controls className="w-full h-full object-contain" src={previewUrl} />
                                    <button onClick={resetRecording} className="absolute top-4 right-4 bg-black/60 text-white p-2.5 rounded-full"><RefreshCw className="w-5 h-5" /></button>
                                </>
                            )}
                        </div>
                    </div>
                )}

                {isSubmitting && processingStatus && (
                    <div className="mb-4 bg-blue-50 text-blue-800 p-3 rounded-lg text-sm flex items-center animate-pulse border border-blue-100">
                        <Loader2 className="animate-spin w-4 h-4 mr-2" />
                        {processingStatus}
                    </div>
                )}

                <div className="flex space-x-4 pt-4 border-t border-gray-100">
                    <button onClick={closeModal} className="flex-1 py-3.5 border border-gray-300 rounded-xl font-bold hover:bg-gray-50">Annulla</button>
                    <button 
                        onClick={handleSubmit}
                        disabled={ (uploadMode === 'upload' && !uploadFile) || (uploadMode === 'record' && !recordedBlob) || isSubmitting }
                        className="flex-1 py-3.5 bg-slate-900 text-white rounded-xl font-bold hover:bg-black disabled:opacity-50 flex justify-center items-center"
                    >
                        {isSubmitting ? <Loader2 className="animate-spin h-5 w-5" /> : 'Invia Video'}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getTalentById, createRequest, getAdminSettings } from '../services/dataService';
import { Talent, User, AdminSettings } from '../types';
import { Loader2, ArrowLeft, ShieldCheck, Clock, CreditCard, Info, CheckCircle2, UserCheck, Mic } from 'lucide-react';

const TalentProfile: React.FC<{ currentUser: User | null }> = ({ currentUser }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [talent, setTalent] = useState<Talent | undefined>();
  const [settings, setSettings] = useState<AdminSettings | null>(null);
  const [loading, setLoading] = useState(true);

  const [recipient, setRecipient] = useState('');
  const [instructions, setInstructions] = useState('');
  const [agreed, setAgreed] = useState(false);

  useEffect(() => {
    const load = async () => {
      if (id) {
        const [t, s] = await Promise.all([getTalentById(id), getAdminSettings()]);
        setTalent(t);
        setSettings(s);
        setLoading(false);
      }
    };
    load();
  }, [id]);

  const handleBooking = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !talent || !settings) return;

    try {
        await createRequest({
            talentId: talent.id,
            fanId: currentUser.id,
            fanName: currentUser.name,
            recipientName: recipient,
            instructions: instructions,
            occasion: "Regalo",
            pricePaid: talent.price
        });
        navigate('/dashboard');
    } catch (e) {
        alert("Errore prenotazione.");
    }
  };

  if (loading) return <div className="p-20 flex justify-center"><Loader2 className="animate-spin" /></div>;
  if (!talent) return <div className="p-20 text-center">Profilo non trovato.</div>;

  return (
    <div className="max-w-6xl mx-auto px-4 py-12">
      <button onClick={() => navigate(-1)} className="flex items-center text-gray-400 mb-8 hover:text-slate-900 transition-colors">
        <ArrowLeft className="w-4 h-4 mr-2" /> Torna alla Home
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-4">
            <div className="bg-white rounded-3xl overflow-hidden shadow-xl border border-gray-100 sticky top-24">
                <img src={talent.avatarUrl} className="w-full aspect-square object-cover" />
                <div className="p-6">
                    <div className="flex items-center gap-2 mb-1">
                        <h1 className="text-2xl font-black text-slate-900">{talent.name}</h1>
                        <ShieldCheck className="w-5 h-5 text-blue-500 fill-current" />
                    </div>
                    <p className="text-slate-500 mb-4">{talent.category}</p>
                    <div className="text-3xl font-black text-slate-900">€{talent.price}</div>

                    <div className="mt-6 pt-6 border-t border-gray-100 space-y-3">
                        <div className="flex items-center text-sm text-gray-600">
                            <UserCheck className="w-4 h-4 mr-2 text-emerald-500" />
                            <span>Identità Verificata via Stripe</span>
                        </div>
                        <div className="flex items-center text-sm text-gray-600">
                            <Clock className="w-4 h-4 mr-2 text-gray-400" />
                            <span>Risposta in {talent.responseTimeDays} giorni</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <div className="lg:col-span-8">
            <div className="bg-white rounded-3xl p-8 shadow-xl border border-gray-100">
                <h2 className="text-2xl font-black mb-8 uppercase tracking-tight">Prenota il tuo Video</h2>

                {/* AUTHENTICITY GUARANTEE BANNER */}
