import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getTalentById, createRequest, getAdminSettings } from '../services/dataService';
import { Talent, User, AdminSettings } from '../types';
import { Loader2, ArrowLeft, ShieldCheck, Clock, CreditCard, Instagram, CheckCircle2, UserCheck, Mic, ExternalLink } from 'lucide-react';

const TalentProfile: React.FC<{ currentUser: User | null }> = ({ currentUser }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [talent, setTalent] = useState<Talent | undefined>();
  const [settings, setSettings] = useState<AdminSettings | null>(null);
  const [loading, setLoading] = useState(true);

  const [recipient, setRecipient] = useState('');
  const [instructions, setInstructions] = useState('');
  const [agreed, setAgreed] = useState(false);

  useEffect(() => {
    const load = async () => {
      if (id) {
        const [t, s] = await Promise.all([getTalentById(id), getAdminSettings()]);
        setTalent(t);
        setSettings(s);
        setLoading(false);
      }
    };
    load();
  }, [id]);

  const handleBooking = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !talent || !settings) return;

    try {
        await createRequest({
            talentId: talent.id,
            fanId: currentUser.id,
            fanName: currentUser.name,
            recipientName: recipient,
            instructions: instructions,
            occasion: "Regalo",
            pricePaid: talent.price
        });
        navigate('/dashboard');
    } catch (e) {
        alert("Errore prenotazione.");
    }
  };

  if (loading) return <div className="p-20 flex justify-center"><Loader2 className="animate-spin" /></div>;
  if (!talent) return <div className="p-20 text-center">Profilo non trovato.</div>;

  const instagramUrl = talent.instagramHandle ? `https://instagram.com/${talent.instagramHandle.replace('@', '')}` : null;

  return (
    <div className="max-w-6xl mx-auto px-4 py-12">
      <button onClick={() => navigate(-1)} className="flex items-center text-gray-400 mb-8 hover:text-slate-900 transition-colors">
        <ArrowLeft className="w-4 h-4 mr-2" /> Torna alla Home
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-4">
            <div className="bg-white rounded-3xl overflow-hidden shadow-xl border border-gray-100 sticky top-24">
                <img src={talent.avatarUrl} className="w-full aspect-square object-cover" />
                <div className="p-6">
                    <div className="flex items-center gap-2 mb-1">
                        <h1 className="text-2xl font-black text-slate-900">{talent.name}</h1>
                        <ShieldCheck className="w-5 h-5 text-blue-500 fill-current" />
                    </div>
                    <p className="text-slate-500 mb-6">{talent.category}</p>

                    {/* INSTAGRAM VERIFIED BADGE */}
                    {talent.isInstagramVerified && talent.instagramHandle && (
                        <a 
                            href={instagramUrl!} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="flex items-center gap-3 p-4 bg-gradient-to-r from-purple-50 to-pink-50 rounded-2xl border border-pink-100 mb-6 group"
                        >
                            <div className="bg-gradient-to-tr from-yellow-400 via-red-500 to-purple-600 p-1.5 rounded-lg text-white shadow-sm">
                                <Instagram className="w-4 h-4" />
                            </div>
                            <div className="flex-1">
                                <p className="text-[10px] font-black text-pink-600 uppercase tracking-widest">Instagram Verificato</p>
                                <p className="text-sm font-bold text-slate-900">{talent.instagramHandle}</p>
                            </div>
                            <ExternalLink className="w-4 h-4 text-pink-300 group-hover:text-pink-600 transition-colors" />
                        </a>
                    )}

                    <div className="text-3xl font-black text-slate-900 mb-6">€{talent.price}</div>

                    <div className="pt-6 border-t border-gray-100 space-y-3">
                        <div className="flex items-center text-sm text-gray-600">
                            <UserCheck className="w-4 h-4 mr-2 text-emerald-500" />
                            <span>Identità certificata Stripe</span>
                        </div>
                        <div className="flex items-center text-sm text-gray-600">
                            <Clock className="w-4 h-4 mr-2 text-gray-400" />
                            <span>Risposta in {talent.responseTimeDays} giorni</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <div className="lg:col-span-8">
            <div className="bg-white rounded-3xl p-8 shadow-xl border border-gray-100">
                <h2 className="text-2xl font-black mb-8 uppercase tracking-tight">Prenota il tuo Video</h2>

                <div className="bg-blue-50 border border-blue-100 rounded-2xl p-6 mb-8">
                    <div className="flex items-start mb-4">
                        <ShieldCheck className="w-6 h-6 text-blue-600 mr-4 flex-shrink-0" />
                        <div>
                            <h4 className="font-bold text-blue-900 text-sm uppercase">Autenticità Garantita</h4>
                            <p className="text-blue-700 text-sm">
                                Questo profilo è stato verificato manualmente tramite l'account Instagram ufficiale.
                            </p>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="bg-white/60 p-3 rounded-xl border border-blue-100 flex items-center">
                            <Mic className="w-4 h-4 text-blue-600 mr-2" />
                            <span className="text-xs text-blue-800 font-bold uppercase">Prova del Nome:</span>
                            <span className="text-xs text-blue-700 ml-1">Deve dire "{recipient || '...'}"</span>
                        </div>
                        <div className="bg-white/60 p-3 rounded-xl border border-blue-100 flex items-center">
                            <CheckCircle2 className="w-4 h-4 text-blue-600 mr-2" />
                            <span className="text-xs text-blue-800 font-bold uppercase">No AI Policy:</span>
                            <span className="text-xs text-blue-700 ml-1">Vietati cloni e deepfake</span>
                        </div>
                    </div>
                </div>

                <form onSubmit={handleBooking} className="space-y-6">
                    <div>
                        <label className="block text-sm font-black uppercase text-slate-400 mb-2">Per chi è il video?</label>
                        <input 
                            className="w-full bg-slate-50 border border-gray-200 rounded-xl p-4 font-medium focus:ring-2 focus:ring-slate-900 outline-none"
                            placeholder="Nome del destinatario..."
                            value={recipient}
                            onChange={e => setRecipient(e.target.value)}
                            required
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-black uppercase text-slate-400 mb-2">Istruzioni (Cosa deve dire?)</label>
                        <textarea 
                            className="w-full bg-slate-50 border border-gray-200 rounded-xl p-4 font-medium focus:ring-2 focus:ring-slate-900 outline-none min-h-[120px]"
                            placeholder="Es: Ciao Marco, buon compleanno per i tuoi 30 anni..."
                            value={instructions}
                            onChange={e => setInstructions(e.target.value)}
                            required
                        />
                    </div>

                    <div className="p-4 bg-slate-50 rounded-xl border border-slate-200 flex items-center gap-3">
                        <input 
                            type="checkbox" 
                            checked={agreed} 
                            onChange={e => setAgreed(e.target.checked)}
                            className="w-5 h-5 rounded accent-slate-900"
                        />
                        <span className="text-xs text-slate-500 font-medium">
                            Accetto che il VIP tratti i miei dati per fini artistici.
                        </span>
                    </div>

                    <button 
                        disabled={!agreed}
                        className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg shadow-xl hover:bg-black transition-all disabled:opacity-30 flex items-center justify-center gap-3"
                    >
                        <CreditCard className="w-6 h-6" />
                        AUTORIZZA €{talent.price}
                    </button>
                </form>
            </div>
        </div>
      </div>
    </div>
  );
};

export default TalentProfile;

import React, { useState, useEffect } from 'react';
import { User, RequestStatus, VideoRequest, AdminSettings, AuditLog, UserRole } from '../types';
import { 
    getAdminSettings, 
    getPendingTalents, 
    approveTalent, 
    getAuditLogs,
    verifyInstagramAdmin
} from '../services/dataService';
import { 
    ShieldCheck, Settings, Users, Activity, FileText, Loader2, RefreshCw, Instagram, Check, X
} from 'lucide-react';

const AdminDashboard: React.FC<{ user: User }> = ({ user }) => {
    const [activeTab, setActiveTab] = useState<'approvals' | 'settings' | 'logs'>('approvals');
    const [loading, setLoading] = useState(true);
    const [pendingTalents, setPendingTalents] = useState<User[]>([]);
    const [logs, setLogs] = useState<AuditLog[]>([]);

    const loadData = async () => {
        setLoading(true);
        const [pending, audit] = await Promise.all([
            getPendingTalents(),
            getAuditLogs()
        ]);
        setPendingTalents(pending);
        setLogs(audit);
        setLoading(false);
    };

    useEffect(() => {
        loadData();
    }, []);

    const handleVerifyIG = async (userId: string, status: boolean) => {
        await verifyInstagramAdmin(userId, status);
        loadData();
    };

    if (user.role !== UserRole.ADMIN) return <div className="p-20 text-center font-bold text-red-600">ACCESSO NEGATO</div>;

    return (
        <div className="max-w-7xl mx-auto px-4 py-8">
            <header className="mb-8 flex items-center justify-between border-b border-gray-200 pb-6">
                <div className="flex items-center">
                    <div className="bg-red-600 p-3 rounded-lg text-white mr-4 shadow-xl">
                        <ShieldCheck className="w-8 h-8" />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black text-slate-900 uppercase">Sala Controllo Admin</h1>
                        <p className="text-sm text-gray-500">Gestione identità e verifica IG</p>
                    </div>
                </div>
                <button onClick={loadData} className="p-2 hover:bg-gray-100 rounded-lg"><RefreshCw className="w-5 h-5 text-gray-400" /></button>
            </header>

            <nav className="flex space-x-1 bg-gray-100 p-1 rounded-xl mb-8 w-fit shadow-inner">
                {[
                    { id: 'approvals', label: 'Verifiche Talent', icon: Users, count: pendingTalents.length },
                    { id: 'logs', label: 'Audit Logs', icon: FileText }
                ].map(tab => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as any)}
                        className={`flex items-center px-4 py-2.5 rounded-lg text-xs font-black uppercase transition-all ${activeTab === tab.id ? 'bg-white text-slate-900 shadow-sm' : 'text-gray-500 hover:text-slate-700'}`}
                    >
                        <tab.icon className="w-4 h-4 mr-2" />
                        {tab.label}
                        {tab.count !== undefined && tab.count > 0 && (
                            <span className="ml-2 bg-red-500 text-white w-5 h-5 rounded-full flex items-center justify-center text-[10px]">{tab.count}</span>
                        )}
                    </button>
                ))}
            </nav>

            {loading ? (
                <div className="flex justify-center py-20"><Loader2 className="w-10 h-10 animate-spin text-slate-400" /></div>
            ) : (
                <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
                    {activeTab === 'approvals' && (
                        <table className="w-full text-left">
                            <thead className="bg-gray-50 text-[10px] font-black uppercase text-gray-400 border-b">
                                <tr>
                                    <th className="p-4">Talent / IG Handle</th>
                                    <th className="p-4">Codice Atteso</th>
                                    <th className="p-4 text-right">Azione Manuale IG</th>
                                    <th className="p-4 text-right">Approvazione CiaoStar</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {pendingTalents.map(t => (
                                    <tr key={t.id} className="hover:bg-slate-50 transition-colors text-sm">
                                        <td className="p-4">
                                            <div className="font-bold text-slate-900">{t.name}</div>
                                            <div className="text-pink-600 flex items-center gap-1">
                                                <Instagram className="w-3 h-3" /> {t.instagramHandle || 'Nessuno'}
                                            </div>
                                        </td>
                                        <td className="p-4">
                                            <span className="bg-slate-100 px-3 py-1 rounded-lg font-black tracking-widest">{t.instagramVerificationCode}</span>
                                        </td>
                                        <td className="p-4 text-right">
                                            {t.isInstagramVerified ? (
                                                <span className="text-emerald-500 font-bold flex items-center justify-end gap-1"><Check className="w-4 h-4"/> VERIFICATO</span>
                                            ) : (
                                                <button 
                                                    onClick={() => handleVerifyIG(t.id, true)}
                                                    className="bg-pink-100 text-pink-700 px-3 py-1.5 rounded-lg text-xs font-black hover:bg-pink-200"
                                                >
                                                    SEGNA COME VERIFICATO IG
                                                </button>
                                            )}
                                        </td>
                                        <td className="p-4 text-right">
                                            <button 
                                                onClick={() => approveTalent(t.id).then(loadData)}
                                                className="bg-slate-900 text-white px-4 py-2 rounded-lg text-xs font-bold"
                                            >
                                                ATTIVA PROFILO
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}

                    {activeTab === 'logs' && (
                        <table className="w-full text-left text-xs">
                            <thead className="bg-gray-50 text-gray-400 font-black uppercase">
                                <tr>
                                    <th className="p-3">Data</th>
                                    <th className="p-3">User</th>
                                    <th className="p-3">Azione</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-50">
                                {logs.map(log => (
                                    <tr key={log.id}>
                                        <td className="p-3 text-gray-400">{new Date(log.timestamp).toLocaleString()}</td>
                                        <td className="p-3 font-medium">{log.userId}</td>
                                        <td className="p-3">{log.action}: {log.details}</td>
                                    </tr>
                                ))}
