import { db, storage, auth } from '../firebaseConfig';
import { 
  collection, addDoc, getDocs, query, where, updateDoc, doc, getDoc, setDoc, 
  orderBy, limit, serverTimestamp, increment, onSnapshot, deleteDoc
} from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { Talent, User, UserRole, VideoRequest, RequestStatus, AdminSettings, AuditLog, ChatMessage, Conversation } from '../types';
import { ADMIN_EMAIL, DEFAULT_ADMIN_SETTINGS, DB_CATEGORIES_SEED } from '../constants';

// --- UTILS ---

const generateIGCode = () => `CS-${Math.floor(1000 + Math.random() * 9000)}`;

export const logAction = async (userId: string, action: string, details: string) => {
    await addDoc(collection(db, 'audit_logs'), { userId, action, details, timestamp: new Date().toISOString() });
};

// --- SETTINGS ---

export const getAdminSettings = async (): Promise<AdminSettings> => {
    const settingsRef = doc(db, 'settings', 'global_config');
    const snap = await getDoc(settingsRef);
    if (snap.exists()) return snap.data() as AdminSettings;
    await setDoc(settingsRef, { ...DEFAULT_ADMIN_SETTINGS, maxDeliveryDays: 7, termsVersion: 1 });
    return { ...DEFAULT_ADMIN_SETTINGS, maxDeliveryDays: 7, termsVersion: 1 } as AdminSettings;
};

// --- USER & IG VERIFICATION ---

export const syncUserToDB = async (user: Partial<User>) => {
  const userRef = doc(db, 'users', user.id!);
  const userSnap = await getDoc(userRef);

  if (!userSnap.exists()) {
    const newUser = {
      ...user,
      role: user.email === ADMIN_EMAIL ? UserRole.ADMIN : (user.role || UserRole.FAN),
      lastAcceptedTermsVersion: 0,
      isApproved: user.email === ADMIN_EMAIL,
      createdAt: new Date().toISOString(),
      // Genera codice IG solo se è un Talent
      instagramVerificationCode: generateIGCode(),
      isInstagramVerified: false
    };
    await setDoc(userRef, newUser);
    return newUser as User;
  }
  return { ...user, ...userSnap.data() } as User;
};

export const updateInstagramHandle = async (userId: string, handle: string) => {
    await updateDoc(doc(db, 'users', userId), { 
        instagramHandle: handle.startsWith('@') ? handle : `@${handle}` 
    });
};

export const verifyInstagramAdmin = async (userId: string, status: boolean) => {
    await updateDoc(doc(db, 'users', userId), { isInstagramVerified: status });
    await logAction('admin', 'verify_instagram', `Utente ${userId} verificato IG: ${status}`);
};

export const acceptNewTerms = async (userId: string, version: number) => {
    await updateDoc(doc(db, 'users', userId), {
        lastAcceptedTermsVersion: version
    });
};

// --- TALENT PROFILE ---

// Fix for missing updateTalentProfile error in TalentSettings.tsx
export const updateTalentProfile = async (userId: string, data: Partial<Talent>) => {
    await updateDoc(doc(db, 'users', userId), data);
};

// Fix for missing getCategories error in Home.tsx and TalentSettings.tsx
export const getCategories = async (): Promise<string[]> => {
    return DB_CATEGORIES_SEED;
};

// Fix for missing uploadAvatar error in TalentSettings.tsx
export const uploadAvatar = async (file: File, userId: string): Promise<string> => {
    const storageRef = ref(storage, `avatars/${userId}_${Date.now()}`);
    await uploadBytes(storageRef, file);
    return getDownloadURL(storageRef);
};

// --- WATERMARK ---

// Fix for missing uploadWatermark error in AdminWatermark.tsx
export const uploadWatermark = async (file: File): Promise<string> => {
    const storageRef = ref(storage, `settings/watermark_${Date.now()}`);
    await uploadBytes(storageRef, file);
    const url = await getDownloadURL(storageRef);
    const settingsRef = doc(db, 'settings', 'global_config');
    await updateDoc(settingsRef, { watermarkUrl: url });
    return url;
};

// Fix for missing deleteWatermark error in AdminWatermark.tsx
export const deleteWatermark = async () => {
    const settingsRef = doc(db, 'settings', 'global_config');
    await updateDoc(settingsRef, { watermarkUrl: null });
};

// --- ORDER LOGIC ---

export const createRequest = async (requestData: Omit<VideoRequest, 'id' | 'status' | 'createdAt' | 'expirationTimestamp' | 'maxDeliveryDaysSnapshot' | 'applicationFee' | 'updatedAt'>) => {
    const settings = await getAdminSettings();
    const now = new Date();
    const expirationDate = new Date(now.getTime() + settings.maxDeliveryDays * 24 * 60 * 60 * 1000);
    const appFee = (requestData.pricePaid * settings.platformFeePercent) / 100;

    const finalOrder: Omit<VideoRequest, 'id'> = {
        ...requestData,
        status: RequestStatus.PENDING,
        createdAt: now.toISOString(),
        updatedAt: now.toISOString(),
        applicationFee: appFee,
        maxDeliveryDaysSnapshot: settings.maxDeliveryDays,
        expirationTimestamp: expirationDate.toISOString()
    };

    const docRef = await addDoc(collection(db, 'orders'), finalOrder);
    return docRef.id;
};

export const getRequestsForUser = async (userId: string, role: UserRole): Promise<VideoRequest[]> => {
    const field = role === UserRole.FAN ? 'fanId' : 'talentId';
    const q = query(collection(db, 'orders'), where(field, '==', userId), orderBy('createdAt', 'desc'));
    const snap = await getDocs(q);
    return snap.docs.map(d => ({ id: d.id, ...d.data() } as VideoRequest));
};

export const getTalents = async (): Promise<Talent[]> => {
    const q = query(collection(db, 'users'), where('role', '==', UserRole.TALENT), where('isApproved', '==', true));
    const snap = await getDocs(q);
    return snap.docs.map(d => ({ id: d.id, ...d.data() } as Talent));
};

export const getTalentById = async (id: string): Promise<Talent | undefined> => {
    const docSnap = await getDoc(doc(db, 'users', id));
    return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } as Talent : undefined;
};

export const getAuditLogs = async (): Promise<AuditLog[]> => {
    const q = query(collection(db, 'audit_logs'), orderBy('timestamp', 'desc'), limit(50));
    const snap = await getDocs(q);
    return snap.docs.map(d => ({ id: d.id, ...d.data() } as AuditLog));
};

export const getPendingTalents = async (): Promise<User[]> => {
    const q = query(collection(db, 'users'), where('role', '==', UserRole.TALENT), where('isApproved', '==', false));
    const snap = await getDocs(q);
    return snap.docs.map(d => ({ id: d.id, ...d.data() } as User));
};

export const approveTalent = async (userId: string) => {
    await updateDoc(doc(db, 'users', userId), { isApproved: true });
};

// --- CHAT SYSTEM ---

// Fix for missing sendMessage error in UserChat.tsx and AdminChat.tsx
export const sendMessage = async (conversationId: string, senderId: string, text: string, isAdmin: boolean) => {
    const msgData = {
        senderId,
        text,
        isAdmin,
        timestamp: serverTimestamp(),
        isEdited: false
    };

    // Add message to subcollection
    await addDoc(collection(db, 'conversations', conversationId, 'messages'), msgData);

    // Update conversation metadata
    const userSnap = await getDoc(doc(db, 'users', conversationId));
    const userData = userSnap.data();

    await setDoc(doc(db, 'conversations', conversationId), {
        userName: userData?.name || 'Utente',
        userAvatar: userData?.avatarUrl || '',
