import { syncUserToDB, getAdminSettings, acceptNewTerms } from './services/dataService';
import { Loader2, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [adminSettings, setAdminSettings] = useState<SettingsType | null>(null);

  useEffect(() => {
    const unsubscribe = firebaseAuth.onAuthStateChanged(auth, async (firebaseUser) => {
      const settings = await getAdminSettings();
      setAdminSettings(settings);

      if (firebaseUser) {
        const dbUser = await syncUserToDB({ 
          id: firebaseUser.uid, 
          email: firebaseUser.email || '', 
          name: firebaseUser.displayName || 'Utente',
          role: UserRole.FAN,
          lastAcceptedTermsVersion: 0
        });
        setUser(dbUser);
      } else {
        setUser(null);
      }
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  const handleAcceptTerms = async () => {
    if (!user || !adminSettings) return;
    await acceptNewTerms(user.id, adminSettings.termsVersion);
    setUser({ ...user, lastAcceptedTermsVersion: adminSettings.termsVersion });
  };

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin" /></div>;

  const needsTermsUpdate = user?.role === UserRole.TALENT && adminSettings && user.lastAcceptedTermsVersion < adminSettings.termsVersion;

  return (
    <Router>
      <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
        <Navbar user={user} onLogout={() => firebaseAuth.signOut(auth)} />

        {needsTermsUpdate && (
            <div className="fixed inset-0 z-[9999] bg-slate-900/90 backdrop-blur-md flex items-center justify-center p-4">
                <div className="bg-white rounded-[40px] p-10 max-w-md w-full shadow-2xl text-center border border-white/20">
                    <div className="w-20 h-20 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
                        <ShieldCheck className="w-10 h-10" />
                    </div>
                    <h2 className="text-2xl font-black text-slate-900 mb-6 uppercase tracking-tight">Regolamento Qualità</h2>
                    <div className="text-slate-600 mb-10 space-y-4 text-sm text-left leading-relaxed">
                        <p className="font-medium">Abbiamo aggiornato la <strong>Carta della Qualità</strong>:</p>
                        <ul className="space-y-3 font-bold text-slate-800">
                            <li className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-amber-500 rounded-full"/> Nomi chiari e udibili.</li>
                            <li className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-amber-500 rounded-full"/> Video superiore ai 20 secondi.</li>
                            <li className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-amber-500 rounded-full"/> Divieto assoluto di AI/Deepfake.</li>
                        </ul>
                    </div>
                    <button 
                        onClick={handleAcceptTerms}
                        className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-sm uppercase shadow-2xl hover:bg-black transition-all"
                    >
                        Accetto e Continuo
                    </button>
                </div>
            </div>
        )}

        <main className="flex-1">
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={!user ? <Login onLogin={() => {}} /> : <Navigate to="/" />} />
              <Route path="/talent/:id" element={<TalentProfile currentUser={user} />} />
              <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
              <Route path="/messages" element={user ? <UserChat user={user} /> : <Navigate to="/login" />} />
              <Route path="/settings" element={user?.role === UserRole.TALENT ? <TalentSettings user={user} /> : <Navigate to="/" />} />

              {/* ADMIN MODULAR AREA */}
              <Route path="/admin" element={user?.role === UserRole.ADMIN ? <AdminIdentity /> : <Navigate to="/" />} />
              <Route path="/admin/orders" element={user?.role === UserRole.ADMIN ? <AdminOrders /> : <Navigate to="/" />} />
              <Route path="/admin/settings" element={user?.role === UserRole.ADMIN ? <AdminSettings /> : <Navigate to="/" />} />
              <Route path="/admin/chat" element={user?.role === UserRole.ADMIN ? <AdminChat user={user} /> : <Navigate to="/" />} />

              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

