    // Rimuoviamo il filtro isApproved dalla query per permettere il caricamento e gestire il default in memoria
    const q = query(collection(db, 'users'), where('role', '==', UserRole.TALENT));
    const snap = await getDocs(q);

    return snap.docs.map(d => {
        const data = d.data();
        return { 
            id: d.id, 
            ...data,
            // Fallback per dati mancanti (specialmente se inseriti manualmente)
            isApproved: data.isApproved ?? true, 
            category: data.category || 'Influencer',
