export const getTalentById = async (id: string): Promise<Talent | undefined> => {
    const docSnap = await getDoc(doc(db, 'users', id));
    if (!docSnap.exists()) return undefined;
    const data = docSnap.data();
    return { 
        id: docSnap.id, 
        ...data,
        isApproved: data.isApproved ?? false,
