import { ShieldCheck, Instagram, Check, X, PlayCircle, Loader2, User as UserIcon, RefreshCw, Eye, Power, Globe } from 'lucide-react';

const AdminIdentity: React.FC = () => {
    const [view, setView] = useState<'pending' | 'all'>('pending');
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedVideo, setSelectedVideo] = useState<string | null>(null);

    const load = async () => {
        setLoading(true);
        try {
            const data = view === 'pending' ? await getPendingTalents() : await getAllTalentsForAdmin();
            setUsers(data);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { load(); }, [view]);

    const handleAction = async (userId: string, action: 'verify_ig' | 'approve' | 'reject' | 'toggle_approval' | 'toggle_ig') => {
        try {
            const user = users.find(u => u.id === userId);
            if (action === 'verify_ig') await verifyInstagramAdmin(userId, true);
            if (action === 'approve') await updateVerificationStatus(userId, 'verified');
            if (action === 'reject') await updateVerificationStatus(userId, 'rejected');
            if (action === 'toggle_approval') await updateUserApprovalStatus(userId, !user?.isApproved);
            if (action === 'toggle_ig') await verifyInstagramAdmin(userId, !user?.isInstagramVerified);
            load();
        } catch (e) {
            alert("Errore durante l'operazione.");
        }
    };

    if (loading) return <div className="p-20 flex justify-center"><Loader2 className="animate-spin" /></div>;

    return (
        <div className="max-w-7xl mx-auto px-4 py-8">
            <header className="mb-10 flex flex-col md:flex-row md:items-center justify-between gap-6 border-b pb-8">
