                    >
                        Richieste ({view === 'pending' ? users.length : '...'})
                    </button>
                    <button 
                        onClick={() => setView('all')}
                        className={`px-6 py-2 rounded-lg text-xs font-black uppercase transition-all ${view === 'all' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`}
                    >
                        Tutti i VIP
