        setTalent(t);
        setSettings(s);
        if (t?.responseTimeDays) setDeadlineDays(t.responseTimeDays);
        setLoading(false);
      }
    };
    load();
  }, [id]);

  const handleRefineWithAI = async () => {
    if (!instructions.trim() || !talent) return;
    setIsRefining(true);
    try {
        const refined = await refineRequestText(instructions, occasion, talent.name);
        setInstructions(refined);
    } catch (e) {
        console.error("AI Refinement failed", e);
    } finally {
        setIsRefining(false);
    }
  };

  const handleBooking = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) {
        navigate('/login');
        return;
    }
    if (!talent || !settings) return;

    try {
        await createRequest({
            talentId: talent.id,
            fanId: currentUser.id,
            fanName: currentUser.name,
            recipientName: recipient,
            instructions: instructions,
            occasion: occasion,
            pricePaid: talent.price
        }, deadlineDays);
        navigate('/dashboard');
    } catch (e) {
        alert("Errore durante la prenotazione. Riprova.");
    }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-gray-50"><Loader2 className="animate-spin w-10 h-10 text-slate-900" /></div>;
  if (!talent) return <div className="p-20 text-center font-bold">Profilo non trovato.</div>;

  const isProfileActive = talent.isApproved && talent.isInstagramVerified;
  const instagramUrl = talent.instagramHandle ? `https://instagram.com/${talent.instagramHandle.replace('@', '')}` : null;

  const now = new Date();
  const deliveryDate = new Date(now.getTime() + (deadlineDays * 24 * 60 * 60 * 1000));
  const formattedDeliveryDate = deliveryDate.toLocaleDateString('it-IT', { day: 'numeric', month: 'long', year: 'numeric' });
  const formattedTime = deliveryDate.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });

  return (
    <div className="min-h-screen bg-[#FDFDFF] pb-12">
      {/* Header Navigation - Più compatto */}
      <div className="max-w-6xl mx-auto px-6 pt-6">
        <button 
          onClick={() => navigate(-1)} 
          className="group flex items-center gap-2 text-slate-400 hover:text-slate-900 transition-all font-black text-[10px] uppercase tracking-widest"
        >
          <ArrowLeft className="w-3.5 h-3.5" /> Torna alla scoperta
        </button>
      </div>

      <div className="max-w-6xl mx-auto px-6 mt-6">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* LEFT COLUMN: IDENTITY & TRUST - Più snella */}
          <div className="lg:col-span-4 space-y-6 lg:sticky lg:top-24">
            <div className="bg-white rounded-[32px] p-1.5 shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
                <div className="relative group aspect-square rounded-[28px] overflow-hidden bg-slate-100">
                    <img src={talent.avatarUrl} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" />
                    {isProfileActive && (
                      <div className="absolute top-4 right-4 bg-white/90 backdrop-blur-md p-2 rounded-xl shadow-lg border border-white/20">
                        <ShieldCheck className="w-5 h-5 text-blue-500" />
                      </div>
                    )}
                </div>

                <div className="p-6">
                    <div className="flex flex-col mb-4">
                        <h1 className="text-3xl font-black text-slate-900 tracking-tighter leading-tight mb-0.5">{talent.name}</h1>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{talent.category}</span>
                    </div>

                    <div className="space-y-3 mb-6">
                        {talent.isInstagramVerified && (
                          <div className="p-4 bg-pink-50/50 rounded-2xl border border-pink-100/50">
                            <div className="flex items-center gap-2 mb-2">
                                <Instagram className="w-4 h-4 text-pink-500" />
                                <span className="text-[9px] font-black text-pink-600 uppercase tracking-widest">Identità Verificata</span>
                            </div>
                            <p className="text-[10px] text-slate-600 leading-relaxed font-medium">
                              Certificato tramite DM da <strong>{talent.instagramHandle}</strong> e video-proof registrato per CiaoStar.
                            </p>
                          </div>
                        )}

                        <div className="flex items-center justify-between p-3.5 bg-slate-50 rounded-xl border border-slate-100">
                            <div className="flex items-center gap-2.5">
                                <Clock className="w-4 h-4 text-slate-400" />
                                <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Risposta Media</span>
                            </div>
                            <span className="text-xs font-black text-slate-900">{talent.responseTimeDays} Giorni</span>
                        </div>
                    </div>

                    <div className="pt-5 border-t border-slate-50 flex items-center justify-between">
                        <div className="flex flex-col">
                            <span className="text-3xl font-black text-slate-900 tracking-tighter">€{talent.price}</span>
                            <span className="text-[9px] font-bold text-slate-400 uppercase">Prezzo Finale</span>
                        </div>
                        <div className="flex items-center gap-1.5 text-[9px] font-black text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-full uppercase">
                          <CheckCircle2 className="w-3 h-3" /> Stripe Safe
                        </div>
                    </div>
                </div>
            </div>

            {/* PAYMENT SECURITY CARD - Compattata */}
            <div className="bg-slate-900 rounded-[32px] p-6 text-white relative overflow-hidden shadow-xl shadow-slate-900/10">
                <div className="relative z-10">
                    <div className="flex items-center gap-3 mb-4">
                        <Lock className="w-4 h-4 text-emerald-400" />
                        <h4 className="text-[10px] font-black uppercase tracking-widest">Sicurezza Escrow</h4>
                    </div>
                    <div className="space-y-3 text-[10px] text-slate-300 leading-relaxed font-medium">
                        <p>Addebito immediato di <strong>€{talent.price}</strong> custodito dalla piattaforma come deposito.</p>
                        <p className="bg-white/5 p-3 rounded-xl border border-white/10">
                          Compenso sbloccato solo dopo consegna e assenza di dispute valide entro 24h. In caso di errore o ritardo, rimborso <strong>totale istantaneo</strong>.
                        </p>
                    </div>
                </div>
            </div>
          </div>

          {/* RIGHT COLUMN: BOOKING WORKFLOW - Ottimizzato lo scroll */}
          <div className="lg:col-span-8">
            <div className="bg-white rounded-[40px] p-8 lg:p-10 shadow-[0_20px_40px_-12px_rgba(0,0,0,0.04)] border border-slate-100">
                <div className="mb-10 flex items-start justify-between">
                    <div>
                        <h2 className="text-4xl font-black text-slate-900 tracking-tighter mb-2">Prenota Video</h2>
                        <p className="text-slate-500 text-sm font-medium">Invia le istruzioni a {talent.name}.</p>
                    </div>
                    <div className="bg-amber-100 px-3 py-1.5 rounded-xl flex items-center gap-2">
                        <Zap className="w-3.5 h-3.5 text-amber-600 fill-current" />
                        <span className="text-[9px] font-black text-amber-700 uppercase tracking-widest">Garantito</span>
                    </div>
                </div>

                {isProfileActive ? (
                    <form onSubmit={handleBooking} className="space-y-8">

                        {/* STEP 1: CONTEXT - Più compatto */}
                        <section className="space-y-6">
                          <div className="flex items-center gap-3">
                            <span className="w-6 h-6 rounded-full bg-slate-900 text-white flex items-center justify-center text-[10px] font-black">1</span>
                            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Occasione e Nome</h3>
                          </div>

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              <div className="space-y-2">
                                  <div className="relative">
                                    <select 
                                        value={occasion}
                                        onChange={e => setOccasion(e.target.value)}
                                        className="w-full bg-slate-50 border border-slate-100 rounded-xl p-4 font-bold text-slate-700 focus:ring-2 focus:ring-slate-900/5 outline-none appearance-none cursor-pointer text-sm"
                                    >
                                        {OCCASIONS.map(occ => <option key={occ} value={occ}>{occ}</option>)}
                                    </select>
                                    <ChevronRight className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 rotate-90 pointer-events-none" />
                                  </div>
                              </div>
                              <input 
                                  className="w-full bg-slate-50 border border-slate-100 rounded-xl p-4 font-bold text-slate-700 focus:ring-2 focus:ring-slate-900/5 outline-none text-sm"
                                  placeholder="Nome del destinatario..."
                                  value={recipient}
                                  onChange={e => setRecipient(e.target.value)}
                                  required
                              />
                          </div>
                        </section>

                        {/* STEP 2: CONTENT - Textarea più intelligente */}
                        <section className="space-y-6">
                          <div className="flex items-center gap-3">
                            <span className="w-6 h-6 rounded-full bg-slate-900 text-white flex items-center justify-center text-[10px] font-black">2</span>
                            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Cosa deve dire?</h3>
                          </div>

                          <div className="bg-slate-50 rounded-2xl border border-slate-100 overflow-hidden transition-all">
                              <div className="flex items-center justify-between px-4 py-2 border-b border-slate-100 bg-white/50">
                                <span className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Istruzioni</span>
                                <span className={`text-[9px] font-black ${instructions.length > 280 ? 'text-red-500' : 'text-slate-300'}`}>
                                    {instructions.length} / 300
                                </span>
                              </div>
                              <textarea 
                                  className="w-full bg-transparent p-5 font-medium text-slate-700 outline-none min-h-[120px] resize-none leading-relaxed text-sm placeholder:text-slate-300"
                                  placeholder={`Racconta a ${talent.name} i dettagli...`}
                                  value={instructions}
                                  onChange={e => setInstructions(e.target.value.substring(0, 300))}
                                  required
                              />
                              <div className="p-3 bg-white/50 border-t border-slate-100 flex justify-end">
                                <button 
                                    type="button"
                                    onClick={handleRefineWithAI}
                                    disabled={isRefining || !instructions.trim()}
                                    className="bg-slate-900 text-white px-4 py-2 rounded-lg text-[9px] font-black uppercase flex items-center gap-2 hover:bg-black transition-all"
                                >
                                    {isRefining ? <Loader2 className="animate-spin w-3 h-3" /> : <Wand2 className="w-3 h-3 text-amber-400" />}
                                    Rendi Magico con AI
                                </button>
                              </div>
                          </div>
                        </section>

                        {/* STEP 3: DELIVERY & CHECKOUT - Integrato in un blocco finale */}
                        <section className="space-y-6 pt-6 border-t border-slate-50">
                          <div className="flex items-center gap-3">
                            <span className="w-6 h-6 rounded-full bg-slate-900 text-white flex items-center justify-center text-[10px] font-black">3</span>
                            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Scadenza e Invio</h3>
                          </div>

                          <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100">
                              <div className="flex items-center justify-between mb-4">
                                  <h4 className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Limite massimo di attesa</h4>
                                  <div className="bg-white px-3 py-1 rounded-lg shadow-sm border border-slate-100 font-black text-slate-900 text-[10px]">{deadlineDays} Giorni</div>
                              </div>
                              <input 
                                  type="range" min="1" max="7" step="1"
                                  value={deadlineDays}
                                  onChange={e => setDeadlineDays(parseInt(e.target.value))}
                                  className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900 mb-6"
                              />

                              <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden">
                                  <div className="absolute top-0 left-0 w-1 h-full bg-slate-900"></div>
                                  <p className="text-slate-900 font-bold text-sm leading-snug">
                                      Video garantito entro le <span className="text-blue-600">ore {formattedTime}</span> del <span className="text-blue-600">{formattedDeliveryDate}</span>. 
                                      In ritardo? Rimborso istantaneo.
                                  </p>
                              </div>
                          </div>

                          <div className="space-y-4">
                              <label className="flex items-start gap-3 cursor-pointer group p-2">
                                  <div className="relative mt-0.5">
                                    <input type="checkbox" checked={agreed} onChange={e => setAgreed(e.target.checked)} className="peer sr-only" />
                                    <div className="w-5 h-5 border-2 border-slate-200 rounded-md peer-checked:bg-slate-900 peer-checked:border-slate-900 transition-all flex items-center justify-center">
                                      <CheckCircle2 className="w-3 h-3 text-white opacity-0 peer-checked:opacity-100" />
                                    </div>
                                  </div>
                                  <div className="flex-1">
                                      <p className="text-[10px] font-black text-slate-900 uppercase">Accetto Condizioni & Deposito di Garanzia</p>
                                      <p className="text-[9px] text-slate-400 font-medium leading-tight">Autorizzo il blocco di €{talent.price}. Uso strettamente personale.</p>
                                  </div>
                              </label>

                              <button 
                                  disabled={!agreed || isRefining || !recipient || !instructions}
                                  className="w-full bg-slate-900 text-white py-5 rounded-[24px] font-black text-lg uppercase tracking-tight shadow-xl hover:bg-black hover:scale-[1.01] transition-all disabled:opacity-20 disabled:grayscale disabled:scale-100 flex items-center justify-center gap-3"
                              >
                                  <CreditCard className="w-5 h-5" />
                                  {currentUser ? `Paga e Invia • €${talent.price}` : 'Accedi per Prenotare'}
                              </button>

                              <p className="text-center text-[9px] font-black text-slate-300 uppercase tracking-[0.2em]">
                                SSL 256-bit Secured • 100% Protezione Fan
                              </p>
                          </div>
                        </section>
                    </form>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center p-10 bg-slate-50 rounded-[40px] border-2 border-dashed border-slate-200">
                        <AlertCircle className="w-12 h-12 text-slate-300 mb-6" />
                        <h3 className="text-xl font-black text-slate-900 uppercase mb-2 tracking-tighter">Profilo in Verifica</h3>
                        <p className="text-slate-500 text-sm font-medium mb-8">Stiamo ultimando i controlli su {talent.name}.</p>
                        <button onClick={() => navigate('/')} className="bg-slate-900 text-white px-8 py-3 rounded-xl font-black uppercase text-[10px] tracking-widest">Torna alla Home</button>
                    </div>
                )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TalentProfile;
